(2965, 'FP1_025', 'Возрождение', '1', '', '', 'Уничтожает существо, а затем возвращает его на поле боя с полным здоровьем.', 'Это как рождение, только во взрослом возрасте и сразу после смерти.', 'Spell', 'Common', '', '1', 'Можно создать после завершения испытания шамана в Наксрамасе.', '', 'Curse of Naxxramas', 'Нет в Стандарте', 'Shaman', 1809),
(2966, '/SCH_514', 'Воскрешение мертвых', '0', '', '', '<b>Сила героя</b>\nОживляет павших существ противника в виде скелетов 1/1.Deal $3 damage to your hero. Return two friendly minions that died this game to your hand.', 'Deal $3 damage to your hero. Return two friendly minions that died this game to your hand.', 'SPELL', 'COMMON', '', '1', '', '', 'SCHOLOMANCE', 'Нет в Стандарте', '', 59223),
(2967, 'FP1_003', 'Делящийся слизнюк', '2', '1', '2', '<b>Боевой клич:</b> в конце вашего хода призывает на поле боя копию этого существа.', 'Слизнюк делится... делится слизнюк!', 'Minion', 'Epic', '', '1', 'Можно создать после победы над Сапфироном в Логове ледяного змея.', 'Боевой клич', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1858),
(2968, 'NAX8_02', 'Жатва', '2', '', '', '<b>Сила героя</b>\nБерет карту.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2969, 'NAX14_03', 'Замороженный герой', '5', '2', '10', 'Постоянно находится под эффектом <b>заморозки</b>. Находящиеся по обе стороны существа получают неуязвимость к Ледяному дыханию.', '', 'Minion', '', '', '', '', 'Aura', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2970, 'NAX9_07', 'Знак всадников', '5', '', '', 'Ваше оружие и ваши существа получают +1/+1.', '', 'Spell', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2971, 'NAX5_02', 'Извержение', '1', '', '', '<b>Сила героя</b>\nНаносит 2 ед. урона крайнему левому существу противника.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2972, 'FP1_012', 'Изрыгатель слизи', '5', '3', '5', '<b>Провокация.\nПредсмертный хрип:</b> призывает на поле боя слизь 1/2 со способностью <b>Провокация.</b>', 'НЕ ПОИТЕ ЕГО ГАЗИРОВКОЙ.', 'Minion', 'Rare', '', '1', 'Можно создать после победы над Лотхибом в Чумном квартале.', 'Предсмертный хрип|провокация', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1793),
(2973, 'NAX12_04', 'Исступление', '3', '', '', 'Ваш герой получает +6 к атаке в этот ход.', '', 'Spell', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2974, 'NAX12_02', 'Истребление', '2', '', '', '<b>Сила героя</b>\n Здоровье всех существ становится равно 1.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2975, 'FP1_027', 'Каменная горгулья', '3', '1', '4', 'Это существо полностью восстанавливает свое здоровье в начале каждого вашего хода.', 'Каменные горгульи очень любят играть в «Море волнуется раз».', 'Minion', 'Common', '', '1', 'Можно создать после победы над Нотом Чумным в Чумном квартале.', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1861),
(2976, 'FP1_013', 'Кел''Тузад', '8', '6', '8', 'В конце каждого хода призывает на поле боя всех ваших существ, которые умерли в этот ход.', 'У Кел''Тузада было очень несчастливое детство. Неудивительно, с таким-то именем!', 'Minion', 'Legendary', '', '1', 'Можно создать после убийства всех боссов Наксрамаса.', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1794),
(2977, 'NAX3_02', 'Кокон', '3', '', '', '<b>Сила героя</b>\nВозвращает случайное существо противника в его руку.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2978, 'FP1_006', 'Конь смерти', '1', '2', '3', '<b>Рывок. Предсмертный хрип:</b> наносит 3 ед. урона вашему герою.', '', 'Minion', '', '', '', '', 'Рывок|предсмертный хрип', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2979, 'NAX7_05', 'Кристалл контроля', '1', '', '', 'Активируйте кристалл, чтобы управлять учениками.', '', 'Spell', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2980, 'NAX10_02', 'Крюк', '3', '5', '', '<b>Предсмертный хрип:</b> это оружие возвращается вам в руку.', '', 'Weapon', '', '', '', '', 'Предсмертный хрип', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0);
