(2981, 'NAX9_02', 'Леди Бломе', '3', '1', '7', 'Ваш герой <b>неуязвим</b>.', '', 'Minion', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2982, 'NAX14_02', 'Ледяное дыхание', '0', '', '', '<b>Сила героя</b>\nУничтожает всех не <b>замороженных</b> существ противника.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2983, 'NAX15_02', 'Ледяной взрыв', '0', '', '', '<b>Сила героя</b>\nНаносит 2 ед. урона герою противника и <b>замораживает</b> его.', '', 'Hero power', '', '', '', '', 'Заморозка', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2984, 'FP1_030', 'Лотхиб', '5', '5', '5', '<b>Боевой клич:</b> в следующий ход противника его заклинания стоят на (5) маны больше.', 'А ведь когда-то Лотхиб был обычным болотным чудищем. Вам не кажется, что давно пора задуматься об экологии Азерота?', 'Minion', 'Legendary', '', '1', 'Можно создать после убийства всех боссов Чумного квартала.', 'Боевой клич', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1914),
(2985, 'FP1_010', 'Мексна', '6', '2', '8', 'Уничтожает любое существо, которому нанесла урон.', 'Мексна очень обижается, когда ее называют «Мекси» или «Максин».', 'Minion', 'Legendary', '', '1', 'Можно создать после убийства всех боссов Паучьего квартала.', 'Отравление', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1791),
(2986, 'NAX6_02', 'Мертвенная аура', '2', '', '', '<b>Сила героя</b>\nНаносит 3 ед. урона герою противника.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2987, 'NAX15_05', 'Мистер Бигглсуорт', '0', '1', '1', '<i>Это любимый кот Кел''Тузада.</i>', '', 'Minion', 'Legendary', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2988, 'FP1_028', 'Могильщик', '1', '1', '2', 'Получает +1/+1, когда вы призываете на поле боя существо со способностью <b>«Предсмертный хрип»</b>.', 'В мире, где каждый умерший первым делом бежит к целителю душ и воскресает, могильщики чуть не остались без работы.', 'Minion', 'Common', '', '1', 'Можно создать после победы над Лоскутиком в Квартале Мерзости.', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1910),
(2989, 'NAX11_04', 'Мутагенный укол', '3', '', '', 'Выбранное существо получает +4/+4 и способность <b>«Провокация»</b>.', '', 'Spell', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2990, 'NAX11_03', 'Мутная слизь', '1', '2', '2', '', '', 'Minion', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2991, 'NAXM_001', 'Некрорыцарь', '4', '5', '6', '<b>Предсмертный хрип:</b> уничтожает находящихся рядом с ним существ.', '', 'Minion', '', '', '', '', 'Предсмертный хрип', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2992, 'NAX3_03', 'Некротический яд', '2', '', '', 'Уничтожает выбранное существо.', '', 'Spell', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2993, 'NAX1h_03', 'Неруб', '2', '4', '4', '', '', 'Minion', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2994, 'NAX1_03', 'Неруб', '2', '3', '1', '', '', 'Minion', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2995, 'FP1_026', 'Неруб-душитель', '4', '5', '5', '<b>Предсмертный хрип:</b> возвращает ваше случайное существо в руку.', 'Сначала его хотели назвать «Неруб, возвращающий существо в руку», но название не влезло на карту.', 'Minion', 'Common', '', '1', 'Можно создать после завершения испытания разбойника в Наксрамасе.', 'Предсмертный хрип', 'Curse of Naxxramas', 'Нет в Стандарте', 'Rogue', 1810),
(2996, 'FP1_007', 'Нерубское яйцо', '2', '0', '2', '<b>Предсмертный хрип:</b> призывает на поле боя неруба 4/4.', 'Яйца – отличный источник белков и нерубов.', 'Minion', 'Free', '', '1', 'Можно создать после победы над Мексной в Паучьем квартале.', 'Предсмертный хрип', 'CORE', 'Стандартный режим', '', 69713),
(2997, 'FP1_024', 'Нестабильный вурдалак', '2', '1', '3', '<b>Провокация</b>. <b>Предсмертный хрип:</b> наносит 1 ед. урона всем существам.', 'Первое, чему учат в школе некромантов – не давать вурдалакам ракетное топливо.', 'Minion', 'Common', '', '1', 'Можно создать после победы над Хейганом Нечестивым в Чумном квартале.', 'Предсмертный хрип|провокация', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1808),
(2998, 'NAX9_06', 'Нечестивая тень', '5', '', '', '<b>Сила героя</b>\n Берет 2 карты.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(2999, 'NAX2_03', 'Огненный ливень', '2', '', '', '<b>Сила героя</b>\nДелает по выстрелу за каждую карту в руке противника.', '', 'Hero power', '', '', '', '', 'Immunetoурон от заклинаний', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3000, 'NAX7_04', 'Огромный клинок', '3', '5', '', 'Наносит двойной урон героям.', '', 'Weapon', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3001, 'FP1_002', 'Одержимый ползун', '2', '1', '2', '<b>Предсмертный хрип:</b> призывает на поле боя двух призрачных пауков 1/1.', 'Ложноарахнофобия: боязнь ложных пауков.', 'Minion', 'Common', '', '1', 'Можно создать после победы над Ануб''Реканом в Паучьем квартале.', 'Предсмертный хрип', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1781),
(3002, 'FP1_020', 'Отмщение', '1', '', '', '<b>Секрет:</b> когда одно из ваших существ умирает, случайное ваше существо получает +3/+2.', 'Однажды несколько паладинов решили создать комитет по справедливому воздаянию. Они хотели назвать свою организацию «Лига справедливости», но юристы их отговорили.', 'Spell', 'Common', '', '1', 'Можно создать после завершения испытания паладина в Наксрамасе.', 'Секрет', 'CORE', 'Нет в Стандарте', 'Paladin', 1804),
(3003, 'NAX11_02', 'Отравленное облако', '2', '', '', '<b>Сила героя</b>\n Наносит 1 ед. урона всем существам. Если какое-либо существо умирает, призывается слизь.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3004, 'NAX1h_04', 'Паучий шелест', '2', '', '', '<b>Сила героя</b>\n Призывает на поле боя неруба 4/4.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3005, 'NAX1_04', 'Паучий шелест', '2', '', '', '<b>Сила героя</b>\n Призывает на поле боя неруба 3/1.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3006, 'NAX2_05', 'Почитатель', '3', '1', '4', 'Герой получает +1 к атаке в свой ход.', '', 'Minion', '', '', '', '', 'Aura', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3007, 'FP1_008', 'Призрачный рыцарь', '5', '4', '6', 'Не может быть целью заклинаний или силы героя.', 'Что общего у чудесных дракончиков и призрачных рыцарей? Они оба любят покушать!', 'Minion', 'Common', '', '1', 'Можно создать после победы над Готиком Жнецом в Военном квартале.', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1789),
(3008, 'FP1_022', 'Призыватель Бездны', '4', '3', '4', '<b>Предсмертный хрип:</b> вы призываете на поле боя случайного демона из вашей руки.', '«Бездна! Эй, Бездна! Ко мне!»', 'Minion', 'Common', '', '1', 'Можно создать после завершения испытания чернокнижника в Наксрамасе.', 'Предсмертный хрип', 'Curse of Naxxramas', 'Нет в Стандарте', 'Warlock', 1806),
(3009, 'FP1_018', 'Раздвоение', '3', '', '', '<b>Секрет:</b> когда умирает ваше существо, вы кладете в руку две его копии.', 'Тот редкий случай, когда вашу учетную запись не заблокируют за удвоение карт.', 'Spell', 'Common', '', '1', 'Можно создать после завершения испытания мага в Наксрамасе.', 'Секрет', 'Curse of Naxxramas', 'Нет в Стандарте', 'Mage', 1801),
(3010, 'NAX1_05', 'Рой саранчи', '7', '', '', 'Наносит $3 ед. урона всем существам противника. Восстанавливает #3 ед. здоровья вашему герою.', '', 'Spell', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3011, 'NAX9_05', 'Рунический клинок', '3', '1', '', 'Если остальные всадники мертвы, получает +3 к атаке.', '', 'Weapon', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3012, 'NAX7_03', 'Сбить с ног', '2', '', '', '<b>Сила героя</b>\n Наносит 3 ед. урона.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3013, 'NAX13_02', 'Сдвиг полярности', '0', '', '', '<b>Сила героя</b>\n Меняет местами атаку и здоровье всех существ.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3014, 'NAX4_03', 'Скелет', '1', '1', '1', '', '', 'Minion', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3015, 'NAXM_002', 'Скелет-кузнец', '3', '4', '3', '<b>Предсмертный хрип:</b> уничтожает оружие противника.', '', 'Minion', '', '', '', '', 'Предсмертный хрип', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3016, 'FP1_014', 'Сталагг', '5', '7', '4', '<b>Предсмертный хрип:</b> если во время этого матча умер Фойген, призывает на поле боя Таддиуса.', 'Сталагг сам придумал себе художественный текст:  "Сталагг хороший!"', 'Minion', 'Legendary', '', '1', 'Можно создать после убийства всех боссов Квартала Мерзости.', 'Предсмертный хрип', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1796),
(3017, 'FP1_016', 'Стенающая душа', '4', '3', '5', '<b>Боевой клич:</b> накладывает эффект <b>немоты</b> на прочих ваших существ.', 'Эта душа так громко стенает, что иногда хочется, чтобы она умела накладывать немоту сама на себя.', 'Minion', 'Rare', '', '1', 'Можно создать после победы над Таддиусом в Квартале Мерзости.', 'Боевой клич', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1799),
(3018, 'NAX13_03', 'Суперзаряд', '2', '', '', 'Ваши существа получают +2 к здоровью.', '', 'Spell', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3019, 'NAX9_04', 'Сэр Зелиек', '3', '1', '7', 'Ваш герой <b>неуязвим</b>.', '', 'Minion', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3020, 'NAX9_03', 'Тан Кортазз', '3', '1', '7', 'Ваш герой <b>неуязвим</b>.', '', 'Minion', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3021, 'FP1_029', 'Танцующие клинки', '3', '4', '4', '<b>Предсмертный хрип:</b> противник берет карту.', 'Больше всего они любят танцевать лезгинку.', 'Minion', 'Common', '', '1', 'Можно создать после победы над инструктором Разувием в Военном квартале.', 'Предсмертный хрип', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1913),
(3022, 'FP1_023', 'Темный сектант', '3', '3', '4', '<b>Предсмертный хрип:</b> увеличивает здоровье вашего случайного существа на 3.', 'Культ Проклятых пришел к выводу, что при наборе новых сектантов лучше не упоминать название их организации.', 'Minion', 'Common', '', '1', 'Можно создать после завершения испытания жреца в Наксрамасе.', 'Предсмертный хрип', 'Curse of Naxxramas', 'Нет в Стандарте', 'Priest', 1807),
(3023, 'FP1_011', 'Тенетник', '1', '1', '1', '<b>Предсмертный хрип:</b> вы кладете в руку случайную карту зверя.', 'Никогда не знаешь, что найдешь в паучьем коконе!', 'Minion', 'Common', '', '1', 'Можно создать после завершения испытания охотника в Наксрамасе.', 'Предсмертный хрип', 'CORE', 'Нет в Стандарте', 'Hunter', 1860),
(3024, 'FP1_005', 'Тень Наксрамаса', '3', '2', '2', '<b>Маскировка.</b> В начале вашего хода получает +1/+1.', 'Тени Наксрамаса ненавидят все живое. Они даже кличку смертным придумали – «живчики».', 'Minion', 'Epic', '', '1', 'Можно создать после победы над Кел''Тузадом в Логове ледяного змея.', 'Маскировка', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1784),
(3025, 'NAX10_03', 'Удар ненависти', '4', '', '', '<b>Сила героя</b>\n Уничтожает существо.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3026, 'FP1_021', 'Укус смерти', '4', '4', '', '<b>Предсмертный хрип:</b> наносит 1 ед. урона всем существам.', 'Кто бы мог подумать, что у смерти есть зубы!', 'Weapon', 'Common', '', '1', 'Можно создать после завершения испытания воина в Наксрамасе.', 'Предсмертный хрип', 'Curse of Naxxramas', 'Нет в Стандарте', 'Warrior', 1805),
(3027, 'NAX7_02', 'Ученик', '2', '0', '7', '<b>Провокация</b>', '', 'Minion', '', '', '', '', 'Провокация', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3028, 'FP1_015', 'Фойген', '5', '4', '7', '<b>Предсмертный хрип:</b> если во время этого матча умер Сталагг, призывает на поле боя Таддиуса.', 'Фойген такой грустный, потому что Сталагга любят больше.', 'Minion', 'Legendary', '', '1', 'Можно создать после убийства всех боссов Квартала Мерзости.', 'Предсмертный хрип', 'Curse of Naxxramas', 'Нет в Стандарте', '', 1797),
(3029, 'NAX15_04', 'Цепи', '8', '', '', '<b>Сила героя</b>\nПолучает контроль над случайным существом противника до конца хода.', '', 'Hero power', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3030, 'NAX12_03', 'Челюсти', '1', '1', '', 'Получает +2 к атаке, когда умирает существо со способностью <b>«Предсмертный хрип»</b>.', '', 'Weapon', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3031, 'NAX14_04', 'Чистый холод', '5', '', '', 'Наносит $8 ед. урона герою противника и <b>замораживает</b> его.', '', 'Spell', '', '', '', '', 'Заморозка', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3032, 'NAX4_05', 'Чума', '6', '', '', 'Уничтожает всех существ, не являющихся скелетами.', '', 'Spell', '', '', '', '', '', 'Curse of Naxxramas', 'Нет в Стандарте', '', 0),
(3033, 'FP1_019', 'Ядовитые семена', '4', '', '', 'Уничтожает всех существ и призывает вместо них древней 2/2.', 'Мы бы вам не советовали покупать булочки, посыпанные этими семенами.', 'Spell', 'Common', '', '1', 'Можно создать после завершения испытания друида в Наксрамасе.', '', 'Curse of Naxxramas', 'Нет в Стандарте', 'Druid', 1802),
(3034, 'EX1_044', 'Авантюрист', '3', '2', '2', 'Каждый раз, когда вы разыгрываете карту, это существо получает +1/+1.', 'Правильнее было бы назвать его «Приключенец», потому что с ним все время что-то приключается.', 'Minion', 'Rare', 'Alliance', '1', '', '', 'Expert', 'Нет в Стандарте', '', 791),
(3035, 'EX1_134', 'Агент ШРУ', '3', '3', '3', '<b>Серия приемов:</b> наносит 2 ед. урона.', 'Агенты ШРУ занимаются секретной деятельностью в интересах Штормграда: шпионажем, убийствами и организацией вечеринок-сюрпризов на дни рождения членов королевской семьи.', 'Minion', 'Free', 'Neutral', '1', '', 'Комбо', 'CORE', 'Стандартный режим', 'Rogue', 69621),
(3036, 'NEW1_010', 'Ал''акир', '8', '3', '5', '<b>Неистовство ветра, Рывок, Божественный щит, Провокация</b>', 'Он самый слабый среди четырех повелителей элементалей, и остальные трое не дают ему забыть об этом.', 'Minion', 'Free', '', '1', '', 'Рывок|божественный щит|провокация|неистовство ветр', 'CORE', 'Стандартный режим', 'Shaman', 69632),
(3037, '/CORE_VAN_EX1_561', 'Алекстраза', '9', '8', '8', '<b>Боевой клич:</b> текущее здоровье выбранного героя становится равно 15.', 'Алекстраза, Хранительница Жизни несет свет и надежду каждому. Кроме Смертокрыла. И Малигоса. И еще Некроса.', 'Minion', 'Legendary', 'Neutral', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 581),
(3038, 'CS2_227', 'Алчный наемник', '5', '7', '6', 'Ваши существа стоят на (3) маны больше.', 'Он может смотреть бесконечно на то, как льется вода, горит огонь и блестит его гонорар.', 'Minion', 'Common', 'Horde', '1', '', 'Aura', 'Expert', 'Нет в Стандарте', '', 1122),
(3039, 'EX1_020', 'Алый крестоносец', '3', '3', '1', '<b>Божественный щит</b>', 'Привезите ей цветочек аленький. Она будет счастлива.', 'Minion', 'Common', 'Alliance', '1', '', 'Божественный щит', 'Expert', 'Нет в Стандарте', '', 642),
(3040, 'EX1_393', 'Аманийский берсерк', '2', '2', '3', '<b>Исступление:</b> +3 к атаке.', 'Если аманийский берсерк спрашивает вас: «Ты это на меня уставился?», правильным ответом будет: «Нее, чувак!»', 'Minion', 'Common', 'Neutral', '1', '', 'Исступление', 'Expert', 'Нет в Стандарте', '', 790),
(3041, 'EX1_287', 'Антимагия', '3', '', '', '<b>Секрет:</b> когда противник разыгрывает заклинание, вы <b>отменяете</b> его.', 'Чем отличается маг, пользующийся Антимагией, от мага, пренебрегающего этим заклинанием? Первый никогда не получит Огненной глыбой по физиономии.', 'Spell', 'Free', 'Neutral', '1', '', 'Секрет', 'CORE', 'Стандартный режим', 'Mage', 69607),
(3042, 'EX1_559', 'Архимаг Антонидас', '7', '5', '7', 'Каждый раз, когда вы разыгрываете карту заклинания, вы кладете карту «Огненный шар» к себе в руку.', 'Антонидас был великим магом Кирин-Тора и учителем Джайны. После предыдущей работы великим зачаровывателем пончиков с джемом это было серьезное повышение.', 'Minion', 'Legendary', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Mage', 1080),
(3043, 'EX1_591', 'Аукенайская жрица', '4', '3', '5', 'Ваши карты и способности, восстанавливающие здоровье, вместо этого наносят урон.', 'Аукенайские жрецы знают, что конец близок, но не уверены, насколько.', 'Minion', 'Rare', 'Neutral', '1', '', 'Aura', 'Expert', 'Нет в Стандарте', 'Priest', 237),
(3044, 'EX1_249', 'Барон Геддон', '7', '7', '5', 'В конце вашего хода наносит 2 ед. урона ВСЕМ остальным персонажам.', 'В детстве его дразнили «Геддон-армагеддон». Он вырос и пошел работать на Рагнароса.', 'Minion', 'Legendary', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', '', 336),
(3045, 'EX1_564', 'Безликий манипулятор', '5', '3', '3', '<b>Боевой клич:</b> становится копией выбранного существа.', 'Безликие – слуги Йогг-Сарона, и они питаются страхом. Вот прямо сейчас они смакуют ваш страх случайно распылить все хорошие карты.', 'Minion', 'Epic', 'Neutral', '1', '', 'Боевой клич', 'CORE', 'Нет в Стандарте', '', 531),
(3046, 'EX1_059', 'Безумный алхимик', '2', '2', '2', '<b>Боевой клич:</b> меняет местами атаку и здоровье выбранного существа.', '«Тебе <i>понравится</i> мой новый рецепт!» — приговаривает он. Да уж... особенно, если вы недовольны количеством ваших конечностей.', 'Minion', 'Free', 'Neutral', '1', '', 'Боевой клич', 'CORE', 'Стандартный режим', '', 69661),
(3047, 'EX1_598', 'Бес', '1', '1', '1', '', '', 'Minion', 'Rare', 'Neutral', '', '', '', 'Expert', 'Нет в Стандарте', '', 0),
(3048, 'EX1_320', 'Бич судьбы', '5', '', '', 'Наносит $2 ед. урона выбранному персонажу. Если это его убьет, на поле боя призывается случайный демон.', 'Настоятельно рекомендуется его избегать.', 'Spell', 'Epic', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Warlock', 23),
(3049, 'EX1_355', 'Благословение силы', '5', '', '', 'Удваивает атаку выбранного существа.', 'Эта карта удваивает все: и радости, и горести.', 'Spell', 'Rare', '', '1', '', '', 'Expert', 'Нет в Стандарте', 'Paladin', 1522),
(3050, 'EX1_161', 'Близость к природе', '1', '', '', 'Уничтожает существо. Ваш противник берет 2 карты.', 'Еще один повержен в прах.', 'Spell', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Druid', 233),
(3051, 'EX1_392', 'Боевая ярость', '2', '', '', 'Вы берете карту за каждого вашего персонажа с неполным здоровьем.', '«Лучше не зли меня. Тебе это не понравится.»', 'Spell', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Warrior', 400),
(3052, 'EX1_349', 'Божественная милость', '3', '', '', 'Вы берете карты до тех пор, пока у вас в руке не будет столько же карт, сколько у вашего противника.', 'Это не просто милость, а божественная милость. Почти такая же, как помыть в гостях посуду.', 'Spell', 'Rare', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Paladin', 679),
(3053, 'CS2_188', 'Бранящийся сержант', '1', '2', '1', '<b>Боевой клич:</b> выбранное существо получает +2 к атаке до конца хода.', 'ПОЛОЖИ МЕНЯ В КОЛОДУ, ТУПИЦА!', 'Minion', 'Free', 'Alliance', '1', '', 'Боевой клич', 'CORE', 'Стандартный режим', '', 69649),
(3054, 'CS2_104', 'Буйство', '2', '', '', 'Существо с неполным здоровьем получает +3/+3.', 'Кто буйный? Я БУЙНЫЙ?!', 'Spell', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Warrior', 1108),
(3055, 'EX1_050', 'Вайш''ирский оракул', '3', '2', '2', '<b>Боевой клич:</b> каждый игрок берет 2 карты.', 'Он может предсказать ваше будущее. В будущем оба игрока будут брать карты.', 'Minion', 'Rare', 'Neutral', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 1016),
(3056, 'EX1_103', 'Вайш''ирский провидец', '3', '2', '3', '<b>Боевой клич:</b> все прочие мурлоки получают +2 к здоровью.', 'Вайш''ирские мурлоки обитают в самых глубоких расщелинах Бездонных глубин. Это доказывает, что от мурлоков нигде нельзя спрятаться.', 'Minion', 'Free', 'Neutral', '1', '', 'Боевой клич', 'CORE', 'Стандартный режим', '', 69666),
(3057, 'NEW1_021', 'Вестник рока', '2', '0', '7', 'В начале вашего хода уничтожает ВСЕХ существ.', 'Столько раз он был близок к истине, предрекая конец света... Он был совершенно уверен, что Катаклизм уж точно положит конец всему сущему.', 'Minion', 'Free', '', '1', '', '', '1810', 'Стандартный режим', '', 76317),
(3058, 'EX1_610', 'Взрывная ловушка', '2', '', '', '<b>Секрет:</b> когда вашего героя атакуют, наносит 2 ед. урона всем персонажам противника.', 'Эта штука не только поймает ваш обед, но и зажарит его для вас!', 'Spell', 'Free', 'Neutral', '1', '', 'Секрет', 'CORE', 'Стандартный режим', 'Hunter', 69603),
(3059, 'EX1_313', 'Владыка преисподней', '4', '5', '6', '<b>Боевой клич:</b> наносит 5 ед. урона вашему герою.', 'Маннорот, Магтеридон и Бруталл мертвы. Но похоже, в преисподней ОЧЕНЬ много владык.', 'Minion', 'Epic', 'Neutral', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', 'Warlock', 783),
(3060, 'EX1_597', 'Владычица бесов', '3', '1', '5', 'В конце вашего хода получает 1 ед. урона и призывает на поле боя беса 1/1.', 'Эта работа нравилась бы ей гораздо больше, если б только бесы не были такими кусачими!', 'Minion', 'Rare', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', '', 926),
(3061, 'CS1_129', 'Внутренний огонь', '1', '', '', 'Атака выбранного существа становится равна его здоровью.', 'Сделать своих существ сильнее – хорошая идея. Начинать разговор в Степях – плохая идея.', 'Spell', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Priest', 376),
(3062, 'EX1_607', 'Внутренняя ярость', '0', '', '', 'Наносит $1 ед. урона выбранному существу. Это существо получает +2 к атаке.', 'На лицо прекрасные, ужасные внутри.', 'Spell', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Warrior', 22),
(3063, 'EX1_162', 'Вожак лютых волков', '2', '2', '2', 'Находящиеся по обе стороны существа получают +1 к атаке.', 'Если по обе стороны находятся одинаковые существа, вожак лютых волков загадывает желание.', 'Minion', 'Free', 'Neutral', '1', '', 'Баф соседей|aura', 'CORE', 'Стандартный режим', '', 69668),
(3064, 'EX1_354', 'Возложение рук', '6', '', '', 'Восстанавливает #8 ед. здоровья. Вы берете 3 карты.', 'Если кому-то нужна рука помощи, не забывайте, что у вас их целых две!', 'Spell', 'Epic', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Paladin', 594),
(3065, 'EX1_258', 'Вольный элементаль', '3', '2', '4', 'Когда вы разыгрываете карту с <b>Перегрузкой</b>, это существо получает +1/+1.', 'В отличие от <i>безвольных</i> элементалей, эти умеют добиваться своего.', 'Minion', 'Common', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', 'Shaman', 774),
(3066, 'EX1_010', 'Ворген-разведчик', '1', '2', '1', '<b>Маскировка</b>', 'Если вы хотите прогнать воргена, который лезет к вам в дом на разведку, просто крикните ему: «Фу! Плохой песик!»', 'Minion', 'Free', 'Alliance', '1', '', 'Маскировка', 'CORE', 'Стандартный режим', '', 69654),
(3067, 'EX1_241', 'Выброс лавы', '3', '', '', 'Наносит $5 ед. урона. <b>Перегрузка:</b> (2)', 'Словно вы хлебнули раскаленной магмы!', 'Spell', 'Rare', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Shaman', 864),
(3068, 'EX1_534', 'Высокогрив саванны', '6', '7', '5', '<b>Предсмертный хрип:</b> призывает на поле боя двух гиен 2/2.', 'Где-то в джунглях, в дремучих джунглях... льва сейчас доедают гиены.', 'Minion', 'Rare', '', '1', '', 'Предсмертный хрип', 'CORE', 'Нет в Стандарте', 'Hunter', 1261),
(3069, 'EX1_309', 'Вытягивание души', '4', '', '', 'Уничтожает существо. Восстанавливает #3 ед. здоровья вашему герою.', 'Лучше не заниматься вытягиванием собственной души, иначе вы рискуете навечно зависнуть в таком состоянии.', 'Spell', 'Free', 'Neutral', '1', '', '', 'CORE', 'Стандартный режим', 'Warlock', 69634),
(3070, 'EX1_531', 'Гиена-падальщица', '2', '2', '2', 'Каждый раз, когда ваш зверь умирает, это существо получает +2/+1.', 'Гиены предпочитают питаться костями кодо или крылатых змеев, но на самом деле они едят практически все. Даже вареный лук.', 'Minion', 'Common', '', '1', '', '', 'CORE', 'Нет в Стандарте', 'Hunter', 1281),
(3071, 'EX1_595', 'Глава культа', '4', '4', '2', 'Когда другое ваше существо умирает, вы берете карту.', 'Между прочим, даже став злобной главой культа, она по-прежнему раз в неделю звонит своим родителям.', 'Minion', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', '', 811),
(3072, 'EX1_131', 'Главарь Братства', '2', '3', '2', '<b>Серия приемов:</b> призывает на поле боя бандита Братства 2/1.', 'Пару лет назад он украл дарственную на город, так что на самом деле весь город <i>действительно</i> принадлежит ему. А еще он называет других ничтожествами, чтобы все знали, какой он злой.', 'Minion', 'Common', 'Neutral', '1', '', 'Комбо', 'Expert', 'Нет в Стандарте', 'Rogue', 201),
(3073, 'EX1_154', 'Гнев', '2', '', '', '<b>Выберите эффект:</b> наносит существу $3 ед. урона; или наносит $1 ед. урона существу и вы берете карту.', 'В кабестанской таверне уверены, что этой карте самое место среди легендарных.', 'Spell', 'Free', 'Neutral', '1', '', '', '1810', 'Стандартный режим', 'Druid', 76288),
(3074, 'EX1_384', 'Гнев карателя', '6', '', '', 'Наносит $8 ед. урона, случайно распределенного между персонажами противника.', 'Бам! Бам! Бам! Бам! Бам! Бам! Бам! Бам!', 'Spell', 'Epic', 'Neutral', '1', '', 'Immunetoурон от заклинаний', 'Expert', 'Нет в Стандарте', 'Paladin', 1174),
(3075, 'EX1_365', 'Гнев небес', '3', '', '', 'Вы берете карту и наносите урон, равный ее стоимости.', 'Ну же, пусть это будет «Огненный великан!»', 'Spell', 'Rare', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Paladin', 435),
(3076, 'EX1_076', 'Гном-призыватель', '2', '2', '2', 'Первое существо, которое вы разыгрываете на каждом ходу, стоит на (1) ману меньше.', 'Размер не имеет значения!', 'Minion', 'Rare', 'Alliance', '1', '', 'Aura', 'Expert', 'Нет в Стандарте', '', 37),
(3077, 'EX1_095', 'Гоблин-аукционист', '7', '4', '4', 'Каждый раз, когда вы разыгрываете заклинание, вы берете карту.', 'Когда-то он заведовал аукционом на черном рынке, но его утомляли постоянные драки среди покупателей.', 'Minion', 'Rare', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', '', 932),
(3078, 'NEW1_017', 'Голодный краб', '1', '1', '2', '<b>Боевой клич:</b> уничтожает выбранного мурлока и получает +2/+2.', 'Сегодня у нас на ужин мурлоки!', 'Minion', 'Epic', '', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 443),
(3079, 'EX1_105', 'Горный великан', '12', '8', '8', 'Стоит на (1) ману меньше за каждую карту в вашей руке.', 'Его мама считает, что у него просто широкая кость.', 'Minion', 'Epic', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', '', 993),
(3080, 'EX1_259', 'Гроза', '3', '', '', 'Наносит $2-$3 ед. урона всем существам противника. <b>Перегрузка:</b> (2)', 'Боюсь, от этой грозы зонтик вам не поможет.', 'Spell', 'Free', 'Neutral', '1', '', '', 'CORE', 'Стандартный режим', 'Shaman', 69629),
(3081, 'EX1_414', 'Громмаш Адский Крик', '8', '4', '9', '<b>Рывок</b>. \n<b>Исступление:</b> +6 к атаке.', 'Громмаш выпил оскверненную кровь Маннорота и обрек орков на зеленую кожу и красные глаза. Возможно, это было не лучшим из его решений.', 'Minion', 'Free', 'Neutral', '1', '', 'Рывок|исступление', 'CORE', 'Стандартный режим', 'Warrior', 69643),
(3082, 'NEW1_038', 'Груул', '8', '7', '7', 'В конце каждого хода получает +1/+1.', 'Груул Драконобой просто хотел погладить дракончика... но не рассчитал силу.', 'Minion', 'Legendary', '', '1', '', '', 'Expert', 'Нет в Стандарте', '', 526),
(3083, 'CS2_053', 'Дальнее зрение', '3', '', '', 'Вы берете карту. Эта карта стоит на (3) маны меньше.', 'Дрек''Тар лишен зрения, но он <i>видит</i>. Понимаете? Если нет, то ничего страшного.', 'Spell', 'Free', 'Neutral', '1', '', '', '1810', 'Стандартный режим', 'Shaman', 76293),
(3084, 'EX1_164', 'Дар природы', '5', '', '', '<b>Выберите эффект:</b> вы получаете 2 кристалла маны; или вы берете 3 карты.', 'Друиды черпают вдохновение во многих вещах: в силе природы, в пении птиц и в шоколадных тортиках.', 'Spell', 'Rare', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', 'Druid', 95),
(3085, 'EX1_046', 'Дворф Черного Железа', '4', '4', '4', '<b>Боевой клич:</b> выбранное существо получает +2 к атаке до конца хода.', 'Дворфы Черного Железа отличаются скверным характером. Принимая во внимание, где это железо выплавляется, в этом нет ничего удивительного.', 'Minion', 'Common', 'Alliance', '1', '', 'Боевой клич', 'CORE', 'Нет в Стандарте', '', 348),
(3086, 'EX1_596', 'Демонический огонь', '2', '', '', 'Наносит $2 ед. урона выбранному существу. Если выбран ваш демон, вместо этого он получает +2/+2.', 'Демонический огонь – это тот же огонь, только ОН НИКОГДА НЕ ГАСНЕТ. А-А, ГОРЮ-Ю!', 'Spell', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Warlock', 1142),
(3087, 'NEW1_018', 'Дерзкая налетчица', '2', '2', '3', '<b>Боевой клич:</b> получает бонус к атаке, равный атаке вашего оружия.', '«Я граблю только семь дней в неделю».', 'Minion', 'Free', '', '1', '', 'Боевой клич', 'CORE', 'Стандартный режим', '', 69677),
(3088, 'EX1_578', 'Дикость', '1', '', '', 'Наносит существу противника урон, равный силе атаки вашего героя.', 'Конечно, встречаются и дикие друиды, но есть и такие, которым больше по душе чашечка чая в спокойной обстановке.', 'Spell', 'Rare', 'Neutral', '1', '', 'Affectedbyspellpower', 'Expert', 'Нет в Стандарте', 'Druid', 481),
(3089, 'DS1_188', 'Длинный лук', '7', '5', '', 'Атакуя, ваш герой не получает урона.', 'Длинный лук позволяет стрелять намного дальше, что особенно полезно при стрельбе по дурно пахнущим целям.', 'Weapon', 'Epic', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Hunter', 311),
(3090, 'EX1_045', 'Древний дозорный', '2', '4', '5', 'Не может атаковать.', 'Почему у вас такое ощущение, что его глаза следят за вами, когда вы проходите мимо?', 'Minion', 'Rare', 'Alliance', '1', '', '', 'Expert', 'Нет в Стандарте', '', 605),
(3091, 'EX1_584', 'Древний маг', '4', '2', '5', '<b>Боевой клич:</b> находящиеся по обе стороны существа получают способность <b>«Урон от заклинаний +1»</b>.', 'Иногда он забывает, куда ему идти, и забредает в чужую игру.', 'Minion', 'Rare', 'Neutral', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 915),
(3092, 'EX1_178', 'Древо войны', '7', '5', '5', '<b>Выберите эффект:</b>\n+5 к атаке; \n или +5 к здоровью и способность <b>«Провокация»</b>.', 'Юные ночные эльфы любят играть в игру «Догони меня, древо войны». Если вас раздавило – вы проиграли.', 'Minion', 'Epic', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', 'Druid', 1035),
(3093, 'NEW1_008', 'Древо мудрости', '7', '5', '5', '<b>Выберите эффект:</b> вы берете две карты; или восстанавливает 5 ед. здоровья.', 'Давайте, попробуйте выцарапать на нем свои инициалы.', 'Minion', 'Epic', '', '1', '', '', '1810', 'Нет в Стандарте', 'Druid', 920),
(3094, 'NEW1_040', 'Дробитель', '6', '4', '4', 'В конце вашего хода вы призываете на поле боя гнолла 2/2 со способностью <b>«Провокация»</b>.', 'Дробитель ужасно сильный. Если вы убьете его, то это значит, что он вам <i>поддался</i>.', 'Minion', 'Legendary', '', '1', '', '', 'Expert', 'Нет в Стандарте', '', 640),
(3095, 'EX1_165', 'Друид когтя', '6', '4', '6', '<b>Выберите эффект:</b> <b>Рывок</b>; или +2 к здоровью и способность <b>«Провокация»</b>.', 'Кошка или медведь? Медведь или кошка? Очень сложный выбор!', 'Minion', 'Common', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', 'Druid', 692),
(3096, 'EX1_248', 'Дух дикого волка', '3', '', '', 'Призывает на поле боя двух духов волка 2/3 со способностью <b>«Провокация»</b>. <b>Перегрузка:</b> (2)', 'Духи волков кусают не слабее обычных волков.', 'Spell', 'Free', 'Neutral', '1', '', '', 'CORE', 'Стандартный режим', 'Shaman', 69626),
(3097, 'CS2_038', 'Дух предков', '2', '', '', 'Выбранное существо получает способность «<b>Предсмертный хрип:</b> после смерти это существо вернется на поле боя».', 'Это была всего лишь царапина.', 'Spell', 'Rare', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Shaman', 404),
(3098, 'EX1_158', 'Душа леса', '3', '', '', 'Ваши существа получают способность <b>«Предсмертный хрип»:</b> призывает на поле боя древня 2/2.', 'Выражение «восстановление лесных массивов» вдруг обрело устрашающее значение.', 'Spell', 'Common', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', 'Druid', 381),
(3099, 'CS2_203', 'Железноклюв', '3', '2', '1', '<b>Боевой клич:</b> накладывает эффект <b>немоты</b> на выбранное существо.', 'Полет совы безмолвен. И вообще совы – не то, чем они кажутся.', 'Minion', 'Common', 'Horde', '1', '', 'Боевой клич', 'CORE', 'Нет в Стандарте', '', 290),
(3100, 'NEW1_019', 'Жонглер кинжалами', '2', '2', '2', 'После того, как вы призвали на поле боя существо, наносит 1 ед. урона случайному персонажу противника.', 'Некоторые отчаянные жонглеры кинжалами меняют профессию и начинают жонглировать бомбами, но еще ни одному не удалось продержаться так долго, чтобы стать одной из карт.', 'Minion', 'Rare', '', '1', '', '', 'Expert', 'Нет в Стандарте', '', 1073),
(3101, 'EX1_583', 'Жрица Элуны', '6', '5', '4', '<b>Боевой клич:</b> восстанавливает 4 ед. здоровья вашему герою.', 'Иногда она врывается на поле боя с криком: «Я несу исцеление во имя Луны!»', 'Minion', 'Common', 'Neutral', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 424),
(3102, 'NEW1_022', 'Жуткий корсар', '4', '3', '3', '<b>Провокация</b>. Стоит на (1) ману меньше за каждую единицу атаки вашего оружия.', 'В переводе с пиратского «Арррр!» означает «Приветствую вас, милостивый государь».', 'Minion', 'Free', '', '1', '', 'Провокация', 'Expert', 'Стандартный режим', '', 102230),
(3103, 'EX1_128', 'Замаскировать', '1', '', '', 'Ваши существа получают способность <b>«Маскировка»</b> до вашего следующего хода.', 'Разбойники все время носят маски, но они не в силах замаскировать собственные чувства. Как начнут жаловаться за жизнь – так ничем их не остановишь!', 'Spell', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Rogue', 990),
(3104, 'EX1_362', 'Заступник Авангарда', '2', '2', '2', '<b>Боевой клич:</b> ваше выбранное существо получает способность <b>«Божественный щит»</b>.', '«Я и не говорю, что ты можешь уклониться от огненного шара. Но с моим щитом тебе это не понадобится.»', 'Minion', 'Free', 'Neutral', '1', '', 'Боевой клич', 'CORE', 'Стандартный режим', 'Paladin', 69611),
(3105, 'EX1_058', 'Заступница син''дорай', '2', '2', '3', '<b>Боевой клич:</b> Находящиеся по обе стороны существа получают способность <b>«Провокация»</b>.', '«Будь джентльменом, подержи щит!»\n\nАндрей М. «Wishmaster»', 'Minion', 'Rare', 'Alliance', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 891),
(3106, 'EX1_093', 'Защитник Аргуса', '4', '2', '3', '<b>Боевой клич:</b> существа, находящиеся по обе стороны, получают +1/+1 и способность <b>«Провокация»</b>.', 'Всем нужны защитники. Даже Аргусу.', 'Minion', 'Rare', 'Alliance', '1', '', 'Боевой клич', 'CORE', 'Нет в Стандарте', '', 763),
(3107, 'NEW1_007', 'Звездопад', '5', '', '', '<b>Выберите эффект:</b> наносит существу $5 ед. урона; или $2 ед. урона всем существам противника.', '«Если вы встретили друида и заметили падающую звезду, не загадывайте желание... Бегите!»\n\nАндрей М. «Wishmaster»', 'Spell', 'Rare', '', '1', '', '', 'Expert', 'Нет в Стандарте', 'Druid', 86),
(3108, 'EX1_549', 'Звериный гнев', '1', '', '', 'Ваш выбранный зверь получает +2 к атаке и <b>неуязвимость</b> до конца хода.', 'Безудержный гнев – лишь внешнее проявление чувств. Под ним скрывается дикая вспыльчивость и легкое недовольство.', 'Spell', 'Epic', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Hunter', 903),
(3109, 'EX1_245', 'Земной шок', '1', '', '', 'Накладывает на выбранное существо эффект <b>немоты</b> и затем наносит ему $1 ед. урона.', 'Почему это заклинание называется «Земной шок», а не «Азеротский шок»?', 'Spell', 'Common', 'Neutral', '1', '', 'Немота', 'Expert', 'Нет в Стандарте', 'Shaman', 767),
(3110, 'EX1_009', 'Злая курица', '1', '1', '1', '<b>Исступление:</b> +5 к атаке.', 'Нет зверя страшнее (или смешнее?), чем разъяренная курица.', 'Minion', 'Rare', '', '1', '', 'Исступление', 'Expert', 'Нет в Стандарте', '', 1688),
(3111, 'CS2_221', 'Зловещий кузнец', '5', '4', '6', '<b>Исступление:</b> ваше оружие получает +2 к атаке.', 'Она выкует вам меч, но сначала вам придется принести ей 5 железных слитков, 3 частицы земли и скальп предыдущего покупателя.', 'Minion', 'Common', 'Horde', '1', '', 'Исступление', 'Expert', 'Нет в Стандарте', '', 61),
(3112, 'EX1_603', 'Злой надсмотрщик', '2', '2', '3', '<b>Боевой клич:</b> наносит 1 ед. урона выбранному существу. При этом существо получает +2 к атаке.', '«Тебе нужно будет прийти на работу в воскресенье.»\n\nЗлой надсмотрщик', 'Minion', 'Common', 'Neutral', '1', '', 'Боевой клич', 'CORE', 'Нет в Стандарте', 'Warrior', 285),
(3113, 'EX1_554', 'Змеиная ловушка', '2', '', '', '<b>Секрет:</b> когда одно из ваших существ будет атаковано, вы призываете на поле боя трех змей 1/1.', 'Змеи! Ну почему именно змеи...', 'Spell', 'Epic', 'Neutral', '1', '', 'Секрет', 'CORE', 'Нет в Стандарте', 'Hunter', 455),
(3114, 'EX1_155', 'Знак природы', '3', '', '', '<b>Выберите эффект:</b> существо получает +4 к атаке; или +4 к здоровью и <b>«Провокацию»</b>.', 'Друиды называют это заклинание «Знак природы». Все остальные называют его «пора принять ванну».', 'Spell', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Druid', 151),
(3115, 'EX1_345', 'Игры разума', '4', '', '', 'Вы призываете на поле боя копию случайного существа из колоды противника.', '«Если в вашей колоде нет легендарных существ, то стоит поискать их в колоде противника.»\n\nСергей К. «Склиф»', 'Spell', 'Epic', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Priest', 145),
(3116, 'EX1_572', 'Изера', '9', '4', '12', 'В конце вашего хода вы берете карту Сна.', 'Изера правит царством Изумрудного Сна. Интересно, есть ли там дорога из желтого кирпича?', 'Minion', 'Legendary', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', '', 1186),
(3117, 'DREAM_03', 'Изумрудный дракон', '4', '7', '6', '', '', 'Minion', '', '', '', '', '', 'Expert', 'Нет в Стандарте', 'Dream', 0),
(3118, 'EX1_614', 'Иллидан Ярость Бури', '6', '7', '5', 'Каждый раз, когда вы разыгрываете карту, на поле боя призывается пламя Аззинота 2/1.', 'Брат Иллидана, Малфурион, заточил его под Хиджалом на десять тысяч лет. Кажется, в их семье не любят прощать обиды.', 'Minion', 'Legendary', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', '', 556),
(3119, 'EX1_170', 'Императорская кобра', '3', '2', '3', 'Уничтожает любое существо, которому нанесла урон.', 'В Низине Шолазар водятся ужасные твари. Если вы собираетесь посетить это место, не забудьте репеллент и латные доспехи.', 'Minion', 'Rare', 'Neutral', '1', '', 'Отравление', 'Expert', 'Нет в Стандарте', '', 1098),
(3120, 'EX1_136', 'Искупление', '1', '', '', '<b>Секрет:</b> когда одно из ваших существ умирает, вы возвращаете его на поле боя с 1 ед. здоровья.', 'Если вас только что воскресили из мертвых, не стоит жаловаться на слабое здоровье.', 'Spell', 'Common', 'Neutral', '1', '', 'Секрет', 'Expert', 'Нет в Стандарте', 'Paladin', 140),
(3121, 'NEW1_024', 'Капитан Зеленямс', '5', '5', '4', '<b>Боевой клич:</b> ваше оружие получает +1/+1.', 'Он должен был вести исполинский корабль на Штормград, но эти противные дети опять все испортили!', 'Minion', 'Legendary', '', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 456),
(3122, 'NEW1_027', 'Капитан Южных морей', '3', '3', '3', 'Другие ваши пираты получают +1/+1.', 'Когда-нибудь он награбит достаточно и закажет себе огромную капитанскую шляпу. Он к ним неравнодушен.', 'Minion', 'Free', '', '1', '', 'Aura', 'CORE', 'Стандартный режим', '', 69679),
(3123, 'EX1_573', 'Кенарий', '9', '5', '8', '<b>Выберите эффект:</b> остальные ваши существа получают +2/+2; или призовите на поле боя двух древней 2/2 со способностью <b>«Провокация»</b>.', 'Да, он действительно полубог. Нет, он не носит рубашки.', 'Minion', 'Legendary', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', 'Druid', 36),
(3124, 'EX1_133', 'Клинок вечных мук', '3', '2', '', '<b>Боевой клич:</b> наносит 1 ед. урона. <b>Серия приемов:</b> вместо этого наносит 2 ед. урона.', 'Клинок вечных мук – запасное оружие Рагнароса. Он пользуется им, когда отдает Сульфурас на полировку.', 'Weapon', 'Rare', 'Neutral', '1', '', 'Боевой клич|комбо', 'Expert', 'Нет в Стандарте', 'Rogue', 391),
(3125, 'EX1_341', 'Колодец Света', '2', '0', '5', 'В начале вашего хода восстанавливает 3 ед. здоровья вашему персонажу с неполным здоровьем.', 'До конца не ясно, то ли люди специально игнорируют Колодец Света, то ли просто его не замечают.', 'Minion', 'Rare', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Priest', 797),
(3126, 'EX1_067', 'Командир Авангарда', '6', '4', '2', '<b>Рывок</b>. <b>Божественный щит</b>.', 'Серебряный Рассвет ревностно оберегает мир от двух явлений: от Плети и от тех, кто лезет в кассу без очереди.', 'Minion', 'Rare', 'Neutral', '1', '', 'Рывок|божественный щит', 'Expert', 'Нет в Стандарте', '', 281),
(3127, 'NEW1_036', 'Командирский крик', '2', '', '', 'Здоровье ваших существ не может опуститься ниже 1 ед. до конца хода. Вы берете карту.', '«Кричите громче! Не держите ярость в себе.» Рекомендация будущим воинам.', 'Spell', 'Rare', '', '1', '', '', 'Expert', 'Нет в Стандарте', 'Warrior', 1026),
(3128, 'EX1_275', 'Конус холода', '3', '', '', '<b>Замораживает</b> выбранное существо и существа по обе стороны от него и наносит им $1 ед. урона.', 'Маги Кирин-Тора издавна создавали Кубики холода, но кубизм вышел из моды лет этак 90 назад.', 'Spell', 'Common', 'Neutral', '1', '', 'Заморозка', 'CORE', 'Нет в Стандарте', 'Mage', 430),
(3129, 'EX1_543', 'Король Круш', '9', '8', '8', '<b>Рывок</b>', 'Лучшая защита от короля Круша – встать за спиной у какого-нибудь неприятного вам существа.', 'Minion', 'Legendary', 'Neutral', '1', '', 'Рывок', 'CORE', 'Нет в Стандарте', 'Hunter', 1144),
(3130, 'EX1_014', 'Король Мукла', '3', '5', '5', '<b>Боевой клич:</b> ваш противник получает 2 банана.', 'Король Мукла бродит по острову Жагуаро в поисках любви.', 'Minion', 'Legendary', '', '1', '', 'Боевой клич', 'CORE', 'Нет в Стандарте', '', 1693),
(3131, 'DREAM_05', 'Кошмар', '0', '', '', 'Выбранное существо получает +5/+5, но будет уничтожено в начале вашего следующего хода.', '', 'Spell', '', '', '', '', '', 'Expert', 'Нет в Стандарте', 'Dream', 0),
(3132, 'CS2_059', 'Кровавый бес', '1', '0', '1', '<b>Маскировка</b>. В конце вашего хода другое ваше случайное существо получает +1 к здоровью.', 'Почему у кровавых бесов глаза желтые? Чтобы лучше прятаться в бананах! Что, вы никогда не видели беса в бананах? Хорошо прячется!', 'Minion', 'Common', 'Neutral', '1', '', 'Маскировка', 'Expert', 'Нет в Стандарте', 'Warlock', 469),
(3133, 'EX1_411', 'Кровавый вой', '7', '7', '', 'Когда вы атакуете существ, это оружие теряет 1 ед. атаки вместо прочности.', 'Это знаменитый топор Громмаша Адского Крика. Каким образом он оказался во владении принца Малчезара — загадка!', 'Weapon', 'Epic', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', 'Warrior', 810),
(3134, 'NEW1_025', 'Кровожадный корсар', '1', '1', '2', '<b>Боевой клич:</b> уменьшает прочность оружия противника на 1.', 'Однажды пират, лежа в больнице, по привычке захватил чужое судно.', 'Minion', 'Rare', '', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 997),
(3135, 'EX1_621', 'Круг исцеления', '0', '', '', 'Восстанавливает #4 ед. здоровья ВСЕМ существам.', 'На самом деле, это не круг.', 'Spell', 'Common', '', '1', '', '', 'Expert', 'Нет в Стандарте', 'Priest', 1362),
(3136, 'EX1_312', 'Круговерть Пустоты', '8', '', '', 'Уничтожает всех существ.', 'Круговерть Пустоты – это то самое место, куда отправляются с поля боя уничтоженные существа.', 'Spell', 'Epic', 'Neutral', '1', '', '', 'EXPERT1\n', 'Нет в Стандарте', 'Warlock', 859),
(3137, 'EX1_110', 'Кэрн Кровавое Копыто', '6', '4', '5', '<b>Предсмертный хрип:</b> призывает на поле боя Бейна Кровавое Копыто 4/5.', 'Лучше не кладите эту карту в колоду Гарроша. У них в последнее время не очень хорошие отношения.', 'Minion', 'Legendary', 'Alliance', '1', '', 'Предсмертный хрип', 'CORE', 'Нет в Стандарте', '', 420),
(3138, 'EX1_284', 'Лазурный дракон', '5', '4', '5', '<b>Урон от заклинаний +1</b>. <b>Боевой клич:</b> вы берете карту.', 'Не называйте их голубыми драконами, они обижаются.', 'Minion', 'Rare', 'Neutral', '1', '', 'Боевой клич|урон от заклинаний', '1810', 'Нет в Стандарте', '', 825),
(3139, 'EX1_295', 'Ледяная глыба', '3', '', '', '<b>Секрет:</b> предотвращает наносимый вашему герою смертельный урон и дает ему <b>неуязвимость</b> до конца хода.', 'Сохраняйте ЛЕДЯНОЕ спокойствие.', 'Spell', 'Epic', 'Neutral', '1', '', 'Секрет', 'Expert', 'Нет в Стандарте', 'Mage', 192),
(3140, 'EX1_289', 'Ледяная преграда', '3', '', '', '<b>Секрет:</b> когда вашего героя атакуют, он получает +8 к броне.', 'Это заклинание первого ранга. Заклинание второго ранга – «Преграда из шоколадного молока».', 'Spell', 'Free', 'Neutral', '1', '', 'Секрет', 'CORE', 'Стандартный режим', 'Mage', 69608),
(3141, 'CS2_031', 'Ледяное копье', '1', '', '', '<b>Замораживает</b> выбранного персонажа. Если персонаж уже <b>заморожен</b>, наносит ему $4 ед. урона.', 'Главное – не сломать эту штуку, иначе вместо ледяного копья вы получите кубики льда, а они не столь эффективны в бою.', 'Spell', 'Common', 'Neutral', '1', '', 'Заморозка', 'Expert', 'Нет в Стандарте', 'Mage', 172),
(3142, 'EX1_283', 'Ледяной элементаль', '6', '5', '5', '<b>Боевой клич:</b> <b>замораживает</b> выбранного персонажа.', 'Морская фигура, ЗАМРИ!', 'Minion', 'Common', 'Neutral', '1', '', 'Боевой клич|заморозка', 'Expert', 'Нет в Стандарте', '', 512),
(3143, 'EX1_029', 'Лепрогном', '1', '1', '1', '<b>Предсмертный хрип:</b> наносит 2 ед. урона герою противника.', 'Он очень хочет с вами подружиться, но постоянно чувствует себя изгоем, что плохо сказывается на его характере.', 'Minion', 'Common', 'Neutral', '1', '', 'Предсмертный хрип', 'Expert', 'Нет в Стандарте', '', 658),
(3144, 'EX1_116', 'Лирой Дженкинс', '5', '6', '2', '<b>Рывок</b>. <b>Боевой клич:</b> призывает на сторону вашего противника двух дракончиков 1/1.', 'Зато у него есть злая курица.', 'Minion', 'Legendary', 'Alliance', '1', '', 'Боевой клич|рывок', 'Expert', 'Нет в Стандарте', '', 559),
(3145, 'EX1_323', 'Лорд Джараксус', '8', '3', '15', '<b>Боевой клич:</b> уничтожает вашего героя и заменяет его лордом Джараксусом.', '«НИЧТОЖНЫЙ ГНОМ! ТВОЯ САМОУВЕРЕННОСТЬ ТЕБЯ ПОГУБИТ!»', 'Minion', 'Free', '', '1', '', 'Боевой клич', 'CORE', 'Стандартный режим', 'Warlock', 69637),
(3146, 'EX1_536', 'Лук Орлиного рога', '3', '3', '', 'Каждый раз, когда открывается ваш <b>Секрет</b>, это оружие получает +1 к прочности.', 'Урок первый: острый конец должен указывать на противника.', 'Weapon', 'Rare', '', '1', '', '', 'Expert', 'Нет в Стандарте', 'Hunter', 1662),
(3147, 'EX1_055', 'Любительница маны', '2', '1', '3', 'Каждый раз, когда вы разыгрываете карту заклинания, получает +2 к атаке до конца хода.', 'Она пытается побороть эту дурную привычку, но после долгого и трудного дня как отказаться от глоточка маны?', 'Minion', 'Rare', 'Alliance', '1', '', '', 'Expert', 'Нет в Стандарте', '', 12),
(3148, 'EX1_612', 'Маг Кирин-Тора', '3', '4', '3', '<b>Боевой клич:</b> следующий <b>Секрет</b>, который вы разыграете на этом ходу, будет стоить (0) маны.', 'Кирин-Тор заседает в парящем городе Даларане. Хотите рецепт парящего Даларана? Два шарика мороженого, один шарик Даларана.', 'Minion', 'Rare', 'Neutral', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', 'Mage', 748),
(3149, 'EX1_012', 'Маг крови Талнос', '2', '1', '1', '<b>Урон от заклинаний +1</b>. <b>Предсмертный хрип:</b> вы берете карту.', 'Он отвечает за проведение ежегодного кровавого бала в Монастыре Алого ордена.', 'Minion', 'Free', 'Neutral', '1', '', 'Предсмертный хрип|урон от заклинаний', 'CORE', 'Стандартный режим', '', 69655),
(3150, 'EX1_616', 'Магический призрак', '2', '2', '2', 'Все существа стоят на (1) ману больше.', 'По ночам они выходят питаться неиспользованными кристаллами маны.', 'Minion', 'Rare', 'Neutral', '1', '', 'Aura', 'Expert', 'Нет в Стандарте', '', 715),
(3151, 'EX1_563', 'Малигос', '9', '4', '12', '<b>Урон от заклинаний +5</b>', 'Малигос терпеть не может, когда смертные пользуются магией. Это выводит его из себя!', 'Minion', 'Legendary', 'Neutral', '1', '', 'Урон от заклинаний', 'Expert', 'Нет в Стандарте', '', 436),
(3152, 'NEW1_012', 'Маназмей', '1', '1', '3', 'Каждый раз, когда вы разыгрываете карту заклинания, это существо получает +1 к атаке.', 'Эти змеи питаются чародейской энергией. Хотя они не представляют большой угрозы, лучше не оставляйте их наедине с ведром маны.', 'Minion', 'Common', '', '1', '', '', 'Expert', 'Нет в Стандарте', 'Mage', 405),
(3153, 'EX1_626', 'Массовое рассеивание', '4', '', '', 'Накладывает на всех существ противника эффект <b>немоты</b>. Вы берете карту.', 'Оно рассеивает все: усиления, способности, заклинания, надежды и мечты.', 'Spell', 'Rare', '', '1', '', 'Немота', 'Expert', 'Нет в Стандарте', 'Priest', 1366),
(3154, 'EX1_402', 'Мастер брони', '2', '1', '4', 'Каждый раз, когда ваше существо получает урон, вы получаете +1 к броне.', 'Ремонтирует за счет средств гильдии.', 'Minion', 'Rare', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', 'Warrior', 596),
(3155, 'NEW1_037', 'Мастер ковки клинков', '2', '1', '3', 'В конце вашего хода другое ваше случайное существо получает +1 к атаке.', 'В последнее время он пытается выковать «молотопор», хотя другие кузнецы не верят в его успех.', 'Minion', 'Rare', '', '1', '', '', 'Expert', 'Нет в Стандарте', '', 351);
INSERT INTO `cards_ru` (`id`, `card_id`, `name`, `mana`, `attack`, `health`, `description`, `text`, `type`, `rarity`, `faction`, `collectible`, `howToGetGold`, `mechanics`, `set`, `race`, `playerClass`, `dbf`) VALUES
(3156, 'NEW1_014', 'Мастер маскировки', '4', '4', '4', '<b>Боевой клич:</b> ваше существо получает <b>«Маскировку»</b>.', 'На самом деле это мужчина-таурен. Не зря же его зовут мастером маскировки.', 'Minion', 'Rare', '', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', 'Rogue', 887),
(3157, 'CS2_146', 'Матрос Южных морей', '1', '2', '1', 'Получает <b>Рывок</b>, пока у вас в руках есть оружие.', 'Он первый подписал петицию об отмене антипиратского закона.', 'Minion', 'Common', 'Alliance', '1', '', '', 'Expert', 'Нет в Стандарте', '', 724),
(3158, 'EX1_085', 'Ментальный техник', '3', '3', '3', '<b>Боевой клич:</b> если у вашего противника есть 4 или более существ, вы получаете контроль над одним из них, выбранным случайно.', 'Технологии контроля над разумом постоянно улучшаются, но до совершенства пока далеко.', 'Minion', 'Rare', 'Alliance', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 734),
(3159, 'EX1_083', 'Мехмастер Замыкалец', '3', '3', '3', '<b>Боевой клич:</b> превращает другое случайное существо в дьявозавра 5/5 или белку 1/1.', 'Мехмастер Замыкалец чуть не потерял свою лицензию мехмастера после великого нашествия белок на Стальгорн.', 'Minion', 'Legendary', 'Alliance', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 570),
(3160, 'EX1_366', 'Меч справедливости', '3', '1', '', 'Каждый раз, когда вы призываете существо на поле боя, оно получает +1/+1, а это оружие теряет 1 ед. прочности.', 'Нарекаю тебя Сыром Рокфором!', 'Weapon', 'Epic', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Paladin', 643),
(3161, 'NEW1_029', 'Миллхаус Манашторм', '2', '4', '4', '<b>Боевой клич:</b> в следующий ход противника его заклинания стоят (0) маны.', '«Давай зажигать, крошка!»', 'Minion', 'Legendary', '', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 855),
(3162, 'EX1_382', 'Миротворец Алдоров', '3', '3', '3', '<b>Боевой клич:</b> атака выбранного существа противника становится равна 1.', 'Алдоры ненавидят две вещи: Провидцев и шансон.', 'Minion', 'Rare', 'Neutral', '1', '', 'Боевой клич', 'CORE', 'Нет в Стандарте', 'Paladin', 1167),
(3163, 'EX1_238', 'Молния', '1', '', '', 'Наносит $3 ед. урона. <b>Перегрузка:</b> (1)', 'Знаете, почему вы сначала видите молнию, а потом слышите гром? Потому что глаза у вас впереди, а уши – сзади!', 'Spell', 'Free', 'Neutral', '1', '', '', 'CORE', 'Стандартный режим', 'Shaman', 69625),
(3164, 'EX1_004', 'Молодая жрица', '1', '2', '1', 'В конце вашего хода другое ваше случайное существо получает +1 к здоровью.', 'Она с нетерпением ждет того дня, когда освоит заклинание «Слово силы: Стойкость» второго ранга.', 'Minion', 'Rare', '', '1', '', '', 'CORE', 'Нет в Стандарте', '', 1634),
(3165, 'CS2_169', 'Молодой дракондор', '1', '1', '1', '<b>Неистовство ветра</b>', 'В их честь таурены назвали свою лучшую команду по тауренболу «Дракондоры».', 'Minion', 'Common', 'Horde', '1', '', 'Неистовство ветра', 'Expert', 'Нет в Стандарте', '', 641),
(3166, 'EX1_049', 'Молодой хмелевар', '2', '3', '2', '<b>Боевой клич:</b> возвращает ваше существо с поля боя в руку.', 'Его отвары пока что далеки от совершенства. «Могушанское темное» вообще пить невозможно.', 'Minion', 'Free', 'Alliance', '1', '', 'Боевой клич', 'CORE', 'Стандартный режим', '', 69660),
(3167, 'EX1_567', 'Молот Рока', '5', '2', '', '<b>Неистовство ветра</b>. <b>Перегрузка:</b> (2)', 'Это легендарное оружие подарил Траллу Оргрим Молот Рока. Совпадение имен — чистая случайность.', 'Weapon', 'Epic', 'Neutral', '1', '', 'Неистовство ветра', 'CORE', 'Нет в Стандарте', 'Shaman', 352),
(3168, 'EX1_611', 'Морозная ловушка', '2', '', '', '<b>Секрет:</b> когда существо противника атакует, возвращает его в руку владельца. Его стоимость увеличивается на (2) маны.', 'От таких шуток мороз по коже!', 'Spell', 'Free', 'Neutral', '1', '', 'Секрет', 'CORE', 'Стандартный режим', 'Hunter', 69604),
(3169, 'EX1_586', 'Морской великан', '10', '8', '8', 'Стоит на (1) ману меньше за каждое другое существо на поле боя.', 'Ночевала тучка золотая на груди морского великана...', 'Minion', 'Epic', 'Neutral', '1', '', '', '1810', 'Нет в Стандарте', '', 211),
(3170, 'EX1_391', 'Мощный удар', '1', '', '', 'Наносит $2 ед. урона выбранному существу. Если оно выживет, вы берете карту.', '«Дун да дун, дун да дун». Если вы слышите, как огр напевает это, значит, бежать уже поздно.', 'Spell', 'Free', 'Neutral', '1', '', '', 'CORE', 'Стандартный режим', 'Warrior', 69638),
(3171, 'EX1_410', 'Мощный удар щитом', '1', '', '', 'Наносит выбранному существу 1 ед. урона за каждую единицу брони вашего героя.', '«Какое оружие лучше? Острое, о котором враг знает, или тупое, на которое он не обращает внимания?» – Искусство быть воином, глава 9', 'Spell', 'Free', 'Neutral', '1', '', 'Affectedbyspellpower', 'CORE', 'Стандартный режим', 'Warrior', 69641),
(3172, 'EX1_509', 'Мурлок-волномут', '1', '1', '2', 'Каждый раз, когда на поле боя призывается мурлок, это существо получает +1 к атаке.', 'Когда они собираются, чтобы вместе помутить волны, с ними лучше не связываться!', 'Minion', 'Free', 'Neutral', '1', '', '', 'CORE', 'Стандартный режим', '', 69675),
(3173, 'EX1_507', 'Мурлок-полководец', '3', '3', '3', 'ВСЕ прочие мурлоки получают +2/+1.', 'Как вы думаете, мурлоки когда-нибудь устают издавать один и тот же звук? Ничего подобного! Мрглглглглглглг!', 'Minion', 'Free', 'Neutral', '1', '', 'Aura', '1810', 'Стандартный режим', '', 76270),
(3174, 'EX1_557', 'Нат Пэгл', '2', '0', '4', 'В начале вашего хода вы с вероятностью 50% берете дополнительную карту.', 'Нат Пэгл, лучший рыболов Азерота! Он изобрел Автоспиннинг 3000, Мегакрючок 3000 и Супернаживку 2099 (последняя все еще испытывается).', 'Minion', 'Legendary', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', '', 1147),
(3175, 'EX1_033', 'Неистовая гарпия', '6', '4', '5', '<b>Неистовство ветра</b>', 'У гарпий омерзительный голос. И это еще мягко сказано.', 'Minion', 'Common', 'Alliance', '1', '', 'Неистовство ветра', 'Expert', 'Нет в Стандарте', '', 567),
(3176, 'EX1_332', 'Немота', '0', '', '', 'Накладывает на существо эффект <b>немоты</b>.', 'Специально для злобных магов, зловещих личей, завывающих из могилы, и для караоке-вечеров в «Угрюмом обжоре».', 'Spell', 'Common', 'Neutral', '1', '', 'Немота', 'Expert', 'Нет в Стандарте', 'Priest', 1189),
(3177, 'NEW1_041', 'Несущийся кодо', '5', '3', '5', '<b>Боевой клич:</b> уничтожает случайное существо противника с атакой 2 или меньше.', 'Как поймать кодо с помощью спичечного коробка, бинокля и пинцета? Нужно посмотреть на кодо через перевернутый бинокль, он станет маленьким-маленьким. Затем его нужно взять пинцетом и поместить в коробок.', 'Minion', 'Rare', '', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 1371),
(3178, 'EX1_560', 'Ноздорму', '9', '8', '8', 'Длительность хода каждого игрока ограничена 15 секундами.', 'Эффективное средство против нерасторопных противников.', 'Minion', 'Legendary', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', '', 411),
(3179, 'EX1_625', 'Облик Тьмы', '2', '', '', 'Сила героя меняется на «Наносит 2 ед. урона». Если уже в <i>Облике тьмы</i> – 3 ед. урона.', '«Да, я жрец. НЕТ, Я НЕ МОГУ ВАС ПОЛЕЧИТЬ!!!»\n\nСергей К. «Склиф»', 'Spell', 'Epic', '', '1', '', '', 'CORE', 'Нет в Стандарте', 'Priest', 1368),
(3180, 'EX1_594', 'Обращение в пар', '3', '', '', '<b>Секрет:</b> уничтожает существо, которое атакует вашего героя.', 'Был ли Катаклизм результатом того, что Смертокрыл проиграл партию, когда противник использовал эту карту? Мы никогда не узнаем.', 'Spell', 'Rare', 'Neutral', '1', '', 'Секрет', 'Expert', 'Нет в Стандарте', 'Mage', 286),
(3181, 'EX1_279', 'Огненная глыба', '10', '', '', 'Наносит $10 ед. урона.', 'Не забудьте злобно рассмеяться, вытащив эту карту из колоды!', 'Spell', 'Epic', 'Neutral', '1', '', '', '1810', 'Нет в Стандарте', 'Mage', 1087),
(3182, 'EX1_319', 'Огненный бес', '1', '3', '2', '<b>Боевой клич:</b> наносит 3 ед. урона вашему герою.', 'Бесы любят зажигать. В буквальном смысле.', 'Minion', 'Free', 'Neutral', '1', '', 'Боевой клич', 'CORE', 'Стандартный режим', 'Warlock', 69636),
(3183, '/CORE_EX1_620', 'Огненный великан', '20', '8', '8', 'Стоит на (1) ману меньше за каждое повреждение, полученное вашим героем.', 'Он весь кипит. ПОТОМУ ЧТО У НЕГО ВНУТРИ ЛАВА!', 'Minion', 'Epic', '', '1', '', '', 'Expert', 'Нет в Стандарте', '', 1372),
(3184, 'CS2_231', 'Огонек', '0', '1', '1', '', 'Если запустить достаточное количество огоньков в эредарского повелителя, тот взорвется. Но почему?', 'Minion', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', '', 179),
(3185, 'EX1_132', 'Око за око', '1', '', '', '<b>Секрет:</b> когда ваш герой получает урон, вы наносите такое же количество урона герою противника.', 'Порой правосудие заключается в ударе кулаком об мягкую щеку.', 'Spell', 'Common', 'Neutral', '1', '', 'Секрет', 'Expert', 'Нет в Стандарте', 'Paladin', 462),
(3186, 'EX1_562', 'Ониксия', '9', '8', '8', '<b>Боевой клич:</b> призывает на вашу сторону дракончиков 1/1, пока поле боя не заполнится.', 'Давным-давно Ониксия плела интриги при королевском дворе Штормграда, выдавая себя за леди Катрану Престор. И как только ей удавалось прятать когтистые лапы и огромные крылья?', 'Minion', 'Legendary', 'Neutral', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 363),
(3187, 'EX1_005', 'Опытный охотник', '4', '4', '2', '<b>Боевой клич:</b> уничтожает существо с атакой 7 или больше.', 'Обычные дьявозавры больше его не вдохновляют. Скоро он будет пытаться поймать Ониксию, вооружившись лишь тупым клинком Крола.', 'Minion', 'Free', '', '1', '', 'Боевой клич', 'CORE', 'Стандартный режим', '', 69652),
(3188, 'EX1_398', 'Оружейница Арати', '4', '3', '3', '<b>Боевой клич:</b> снаряжает вас оружием 2/2.', 'Скидка 50% на кистевое оружие. Предложение ограничено!', 'Minion', 'Common', 'Neutral', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', 'Warrior', 538),
(3189, 'CS2_152', 'Оруженосец', '1', '2', '2', '', '', 'Minion', 'Common', 'Alliance', '', '', '', 'Expert', 'Нет в Стандарте', '', 0),
(3190, 'EX1_544', 'Осветительная ракета', '1', '', '', 'Все существа теряют <b>«Маскировку»</b>. Уничтожает все <b>Секреты</b> противника. Вы берете карту.', 'С этой штукой вам будут рады на любой вечеринке!', 'Spell', 'Rare', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Hunter', 896),
(3191, 'EX1_294', 'Отраженная сущность', '3', '', '', '<b>Секрет:</b> когда противник разыгрывает карту существа, вы призываете на свою сторону его копию.', '«Ты пойдешь первым», – сказал Краш''гор по прозвищу Чудовище своему ручному кабану.', 'Spell', 'Common', 'Neutral', '1', '', 'Секрет', 'CORE', 'Нет в Стандарте', 'Mage', 195),
(3192, 'EX1_533', 'Перенаправление', '2', '', '', '<b>Секрет:</b> когда персонаж атакует вашего героя, вместо этого он атакует другого случайного персонажа.', 'Иногда это так же просто, как позвонить в чью-то дверь и выбежать из подъезда.', 'Spell', 'Rare', 'Neutral', '1', '', 'Секрет', 'Expert', 'Нет в Стандарте', 'Hunter', 1091),
(3193, 'EX1_316', 'Переполняющая мощь', '1', '', '', 'Ваше существо получает +4/+4 до конца хода. Потом оно умирает. Ужасной смертью.', 'У нас не хватит слов, чтобы описать, насколько ужасна будет его смерть. Чудовищно ужасна! Или даже хуже... В общем, пожалейте бедное существо.', 'Spell', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Warlock', 846),
(3194, 'EX1_363', 'Печать мудрости', '1', '', '', 'Выберите существо. Когда оно атакует, вы берете карту.', 'Очевидно, с мудростью приходит понимание, что атаковать надо на каждом ходу.', 'Spell', 'Common', '', '1', '', '', 'Expert', 'Нет в Стандарте', 'Paladin', 1373),
(3195, 'EX1_303', 'Пламя Тьмы', '4', '', '', 'Уничтожает ваше существо и наносит урон, равный его атаке, всем существам противника.', 'Возьмите мощное существо, добавьте пламя Тьмы и развлекайтесь в свое удовольствие!', 'Spell', 'Rare', 'Neutral', '1', '', 'Affectedbyspellpower', 'Expert', 'Нет в Стандарте', 'Warlock', 147),
(3196, 'tt_004', 'Плотоядный вурдалак', '3', '2', '3', 'Каждый раз, когда умирает существо, плотоядный вурдалак получает +1 к атаке.', 'Да, он ест трупы. Но как будто у него есть выбор.', 'Minion', 'Common', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', '', 397),
(3197, 'EX1_097', 'Поганище', '5', '4', '4', '<b>Провокация</b>. <b>Предсмертный хрип:</b> наносит 2 ед. урона ВСЕМ персонажам.', 'Поганища любят свежее мясо и долгие прогулки по берегу.', 'Minion', 'Rare', 'Neutral', '1', '', 'Предсмертный хрип|провокация', 'Expert', 'Нет в Стандарте', '', 440),
(3198, 'EX1_145', 'Подготовка', '0', '', '', 'Следующее заклинание, которое вы разыграете на этом ходу, стоит на (3) маны меньше.', '«Главное – хорошая подготовка.» Девиз разбойников.', 'Spell', 'Free', 'Neutral', '1', '', '', 'CORE', 'Стандартный режим', 'Rogue', 69623),
(3199, 'EX1_379', 'Покаяние', '1', '', '', '<b>Секрет:</b> когда противник разыгрывает карту существа, здоровье этого существа становится равно 1.', 'Любопытно, но покаяние зачастую приходит за секунду до гибели.', 'Spell', 'Common', 'Neutral', '1', '', 'Секрет', 'Expert', 'Нет в Стандарте', 'Paladin', 232),
(3200, 'EX1_335', 'Порождение Света', '4', '0', '5', 'Атака этого существа всегда равна его здоровью.', 'Не потому, что рядом с ним светло, а потому, что с ним не надо света.', 'Minion', 'Common', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', 'Priest', 886),
(3201, 'EX1_315', 'Портал призыва', '4', '0', '4', 'Ваши существа стоят на (2) маны меньше, но не меньше (1).', 'НЕ МЕНЬШЕ 1! И торг здесь неуместен.', 'Minion', 'Common', 'Neutral', '1', '', 'Aura', 'Expert', 'Нет в Стандарте', 'Warlock', 969),
(3202, 'EX1_407', 'Потасовка', '5', '', '', 'Уничтожает все существа, кроме одного, выбранного в <i>случайном порядке</i>.', 'Знаете первое правило Бойцовского клуба?', 'Spell', 'Free', 'Neutral', '1', '', '', 'CORE', 'Стандартный режим', 'Warrior', 69640),
(3203, 'EX1_124', 'Потрошение', '2', '', '', 'Наносит $2 ед. урона. <b>Серия приемов:</b> вместо этого наносит $4 ед. урона.', 'За потрошение вашего противника придется заплатить высокую цену: пятна крови очень плохо отмываются от кожаной брони.', 'Spell', 'Free', 'Neutral', '1', '', 'Комбо', 'Expert', 'Стандартный режим', 'Rogue', 102205),
(3204, 'NEW1_005', 'Похититель', '6', '5', '3', '<b>Серия приемов:</b> возвращает выбранное существо в руку владельца.', 'Он вовсе не злой. Просто ему не с кем поговорить.', 'Minion', 'Epic', '', '1', '', 'Комбо', 'Expert', 'Нет в Стандарте', 'Rogue', 287),
(3205, 'EX1_126', 'Предательство', '2', '', '', 'Выбранное существо противника наносит урон, равный своей атаке, существам, находящимся по обе стороны от него.', 'У каждого есть цена. Гномы, например, сделают что угодно за мягкую игрушку и плитку шоколада.', 'Spell', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Rogue', 282),
(3206, 'DREAM_02', 'Пробуждение Изеры', '2', '', '', 'Наносит $5 ед. урона всем персонажам, кроме Изеры.', '', 'Spell', '', '', '', '', '', 'Expert', 'Нет в Стандарте', 'Dream', 0),
(3207, 'EX1_021', 'Провидец Траллмара', '3', '2', '3', '<b>Неистовство ветра</b>', 'Он служит на Полуострове Адского Пламени, но мечтает, чтобы его перевели в Оргриммар или куда-нибудь, где не так много огня.', 'Minion', 'Common', 'Horde', '1', '', 'Неистовство ветра', 'Expert', 'Нет в Стандарте', '', 765),
(3208, 'EX1_350', 'Пророк Велен', '7', '7', '7', 'Ваши заклинания и сила героя восстанавливают здоровье и наносят урон в двойном объеме.', 'Он был изгнан из родного дома, его братья обратились ко злу, но в остальном у него все хорошо!', 'Minion', 'Legendary', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Priest', 9),
(3209, 'EX1_243', 'Пыледемон', '1', '3', '1', '<b>Неистовство ветра</b>. <b>Перегрузка:</b> (2)', 'В Западном Крае полно пыледемонов. И канюков. А еще бешеных големов и пиратов. Интересно, почему там вообще хоть кто-то живет?', 'Minion', 'Common', 'Neutral', '1', '', 'Неистовство ветра', 'Expert', 'Нет в Стандарте', 'Shaman', 618),
(3210, 'EX1_619', 'Равенство', '2', '', '', 'Здоровье ВСЕХ существ становится равно 1.', 'Все существа по-своему неповторимы... пока им это позволяет здоровье.', 'Spell', 'Free', 'Neutral', '1', '', '', 'CORE', 'Стандартный режим', 'Paladin', 69614),
(3211, 'EX1_298', 'Рагнарос', '8', '8', '8', 'Не может атаковать. В конце вашего хода наносит 8 ед. урона случайному персонажу противника.', 'Рагнароса призвали дворфы клана Черного Железа, и это закончилось тем, что Повелитель огня их поработил. Мораль: не призывайте Рагнароса, это может плохо кончиться.', 'Minion', 'Free', 'Neutral', '1', '', '', 'Expert', 'Стандартный режим', '', 102272),
(3212, 'EX1_251', 'Раздвоенная молния', '1', '', '', 'Наносит $2 ед. урона двум случайным существам противника. <b>Перегрузка:</b> (2)', 'Идеальное орудие для убийства сразу двух зайцев.', 'Spell', 'Common', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Shaman', 299),
(3213, 'EX1_102', 'Разрушитель', '3', '1', '4', 'В начале вашего хода наносит 2 ед. урона случайному персонажу противника.', 'Какой смысл начинать осаду, когда нынче почти у всех есть летающие средства передвижения?', 'Minion', 'Rare', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', '', 979),
(3214, 'EX1_048', 'Разрушитель чар', '4', '4', '3', '<b>Боевой клич:</b> накладывает эффект <b>немоты</b> на выбранное существо.', 'Разрушители чар могут вырывать заклинания у магических существ. Операция совершенно безболезненна и проводится в амбулаторных условиях.', 'Minion', 'Common', 'Horde', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 754),
(3215, 'EX1_537', 'Разрывной выстрел', '5', '', '', 'Наносит $5 ед. урона выбранному существу и $2 ед. урона существам, находящимся по обе стороны от него.', 'Взведите курок, досчитайте до пяти и стреляйте. Затем пригнитесь.', 'Spell', 'Rare', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Hunter', 394),
(3216, 'EX1_604', 'Разъяренный берсерк', '3', '2', '4', 'Когда любое существо получает урон, разъяренный берсерк получает +1 к атаке.', 'До того как стать берсерком, он работал бухгалтером.', 'Minion', 'Free', 'Neutral', '1', '', '', 'CORE', 'Стандартный режим', 'Warrior', 69645),
(3217, 'EX1_412', 'Разъяренный ворген', '3', '3', '3', '<b>Исступление:</b> <b>Неистовство ветра</b> и +1 к атаке.', 'Если он уже сейчас разьярен, что же будет, если жестокие разработчики урежут его способности?', 'Minion', 'Common', 'Neutral', '1', '', 'Исступление', 'Expert', 'Нет в Стандарте', '', 1155),
(3218, 'CS2_181', 'Раненый рубака', '3', '4', '7', '<b>Боевой клич:</b> наносит 4 ед. урона самому себе.', 'Он утверждает, что получил эту рану в бою, но, по-моему, он просто порезался, когда брился.', 'Minion', 'Rare', 'Horde', '1', '', 'Боевой клич', 'CORE', 'Нет в Стандарте', '', 1109),
(3219, 'CS2_151', 'Рыцарь Длани', '5', '4', '4', '<b>Боевой клич:</b> призывает на поле боя оруженосца 2/2.', 'Хорошо быть рыцарем. Гораздо лучше, чем оруженосцем.', 'Minion', 'Common', 'Alliance', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 69),
(3220, 'EX1_590', 'Рыцарь крови', '3', '3', '3', '<b>Боевой клич:</b> все существа теряют <b>«Божественный щит»</b>. Рыцарь получает +3/+3 за каждый поглощенный щит.', 'Рыцари крови черпают божественные силы из Солнечного Колодца. Ведрами.', 'Minion', 'Epic', 'Neutral', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 755),
(3221, 'EX1_130', 'Самопожертвование', '1', '', '', '<b>Секрет:</b> когда персонаж противника атакует, вы призываете на поле боя защитника 2/1, который принимает на себя удар.', 'Вечная тебе память, защитник!', 'Spell', 'Common', 'Neutral', '1', '', 'Секрет', 'CORE', 'Нет в Стандарте', 'Paladin', 584),
(3222, 'EX1_624', 'Священный огонь', '6', '', '', 'Наносит $5 ед. урона. Восстанавливает #5 ед. здоровья вашему герою.', 'Священный огонь не бывает без священного дыма!', 'Spell', 'Rare', '', '1', '', '', 'Expert', 'Нет в Стандарте', 'Priest', 1365),
(3223, 'EX1_160', 'Сила дикой природы', '2', '', '', '<b>Выберите эффект:</b> ваши существа получают +1/+1; или призовите на поле боя пантеру 3/2.', 'Если вы встретили пантеру, не смотрите ей в глаза, если хотите выжить. Или наоборот, надо смотреть ей в глаза? В общем, что-то из этого должно сработать...', 'Spell', 'Free', 'Neutral', '1', '', '', 'CORE', 'Стандартный режим', 'Druid', 69593),
(3224, 'EX1_571', 'Сила природы', '5', '', '', 'Призывает на поле боя трех древней 2/2 со способностью <b>«Рывок»</b>, которые умрут в конце хода.', '«Я хочу прикорнуть под этими деревьями. Эй, что это? АААААААА!» – Микрутень, невезучий гном.', 'Spell', 'Epic', 'Neutral', '1', '', '', 'CORE', 'Нет в Стандарте', 'Druid', 493),
(3225, 'EX1_016', 'Сильвана Ветрокрылая', '6', '5', '5', '<b>Предсмертный хрип:</b> вы получаете контроль над случайным существом противника.', 'Артас превратил Сильвану в королеву банши. Какое оскорбление! Право, лучше бы он ее убил...', 'Minion', 'Legendary', '', '1', '', 'Предсмертный хрип', 'Expert', 'Нет в Стандарте', '', 1721),
(3226, 'EX1_008', 'Сквайр Авангарда', '1', '1', '1', '<b>Божественный щит</b>', '«Торжественно клянусь защищать дело Света, очищать мир от Тьмы и есть только обезжиренный йогурт.»\nОбет ордена Серебряного Рассвета', 'Minion', 'Common', 'Alliance', '1', '', 'Божественный щит', 'CORE', 'Нет в Стандарте', '', 757),
(3227, 'CS2_161', 'Скрытный убийца', '7', '7', '5', '<b>Маскировка</b>', 'Просто отправьте ему посылкой 10 000 золота и вложите записку с именем. Все остальное он берет на себя.', 'Minion', 'Rare', 'Alliance', '1', '', 'Маскировка', 'Expert', 'Нет в Стандарте', '', 134),
(3228, 'CS2_117', 'Служитель Земли', '3', '3', '3', '<b>Боевой клич:</b> восстанавливает 3 ед. здоровья.', 'Как же он спит, если его глаза всегда открыты?', 'Minion', 'Common', '', '1', '', 'Боевой клич', 'CORE', 'Нет в Стандарте', '', 1651),
(3229, 'EX1_007', 'Служитель боли', '3', '1', '3', 'Каждый раз, когда это существо получает урон, вы берете карту.', 'Вообще-то он учился на служителя радости, но что-то пошло не так...', 'Minion', 'Free', '', '1', '', '', '1810', 'Стандартный режим', '', 76316),
(3230, 'EX1_032', 'Служительница солнца', '6', '4', '5', '<b>Провокация</b>. <b>Божественный щит</b>.', 'На самом деле, она не служит солнцу. Просто ее так зовут!', 'Minion', 'Rare', 'Alliance', '1', '', 'Божественный щит|провокация', 'Expert', 'Нет в Стандарте', '', 759),
(3231, 'EX1_617', 'Смертельный выстрел', '3', '', '', 'Уничтожает случайное существо противника.', 'Точность не очень ценится среди мок''натальских охотников, в отличие от смертоносности.', 'Spell', 'Free', 'Neutral', '1', '', '', 'CORE', 'Стандартный режим', 'Hunter', 69605),
(3232, 'EX1_408', 'Смертельный удар', '4', '', '', 'Наносит $4 ед. урона. Если у вашего героя 12 или меньше ед. здоровья, вместо этого наносит $6 ед. урона.', '«Если вы используете только одну способность, выбирайте «Смертельный удар» – Кодекс воина, строка 6', 'Spell', 'Rare', 'Neutral', '1', '', '', 'Expert', 'Нет в Стандарте', 'Warrior', 804),
(3233, 'NEW1_030', 'Смертокрыл', '10', '12', '12', '<b>Боевой клич:</b> уничтожает все прочие существа. Вы сбрасываете все карты из вашей руки.', 'Однажды дракон Смертокрыл (ранее известный как Нелтарион) сошел с ума и чуть не разрушил Азерот, но его остановили. Может, ему надо было чаще бывать на свежем воздухе?', 'Minion', 'Legendary', '', '1', '', 'Боевой клич', 'Expert', 'Нет в Стандарте', '', 834),
