(3235, 'EX1_609', 'Снайперский выстрел', '2', '', '', '<b>Секрет:</b> когда ваш противник разыгрывает карту существа, оно получает $4 ед. урона.', 'Великий снайпер всегда попадает в яблочко. Или в яблоню. Или в кабанчика под ней. В общем, великий снайпер никогда не останется голодным!', 'Spell', 'Common', 'Neutral', '1', '', 'Секрет', 'Expert', 'Нет в Стандарте', 'Hunter', 814),
(3236, 'CS2_028', 'Снежная буря', '6', '', '', 'Наносит $2 ед. урона всем существам противника и <b>замораживает</b> их.', 'Осторожно. Говорят, это эпическое заклинание отвлекает детей от школы.', 'Spell', 'Free', 'Neutral', '1', '', 'Заморозка', '1810', 'Стандартный режим', 'Mage', 76273),
(3237, 'EX1_096', 'Собиратель сокровищ', '2', '2', '1', '<b>Предсмертный хрип:</b> вы берете карту.', 'Всегда выбирайте «Мне это нужно».', 'Minion', 'Free', 'Neutral', '1', '', 'Предсмертный хрип', 'CORE', 'Стандартный режим', '', 69665),
(3238, 'DREAM_04', 'Сон', '0', '', '', 'Возвращает выбранное существо в руку владельца.', '', 'Spell', '', '', '', '', '', 'Expert', 'Нет в Стандарте', 'Dream', 0),
(3239, 'EX1_538', 'Спустить собак', '3', '', '', 'За каждое существо противника призывает по гончей 1/1 со способностью <b>«Рывок»</b>.', 'Громко зачитывайте название этой карты каждый раз, когда будете ее разыгрывать.', 'Spell', 'Common', '', '1', '', '', 'Expert', 'Нет в Стандарте', 'Hunter', 1243),
