(3828, 'KAR_073', 'Портал: Водоворот', '2', '', '', 'Наносит $1 ед. урона существам противника. Призывает случайное существо за 1 ману.', 'Этот аттракцион так популярен, что ни один посетитель еще не вернулся с жалобой. С похвалой, впрочем, тоже...', 'Spell', 'Rare', '', '1', '', '', '1810', 'Нет в Стандарте', 'Shaman', 39712),
(3829, 'KAR_028', 'Несчастье шута', '5', '3', '', 'Атакует неограниченное число раз за ход. Не_может атаковать героев.', 'Это был его самый печальный день.', 'Weapon', 'Common', '', '1', '', '', 'KARA', 'Нет в Стандарте', 'Warrior', 39417),
(3830, 'KAR_006', 'Скрытная охотница', '3', '3', '4', 'Ваши <b>секреты</b> стоят (0)_маны.', 'Ваши секреты для нее ничего не стоят.', 'Minion', 'Common', '', '1', '', '', '1810', 'Нет в Стандарте', 'Hunter', 39492),
