(8605, 'GDB_103', 'Маскировочное поле Ша''тар', '2', '1', '4', '<b>Неуловимость</b>\r\nВаше первое заклинание\r\n на каждом ходу стоит на (1) меньше. <b>Часть звездолета</b>.', '', 'MINION', 'COMMON', '', '1', '', 'AURA,STARSHIP_PIECE', 'SPACE', 'Стандартный режим', 'DRUID', 110111),
(8606, 'GDB_104', 'Двигатели Скверны', '3', '2', '4', '<b><b>Резонанс</b>:</b> наносит 2 случайным существам противника урон, равный атаке этого существа. <b>Часть звездолета</b>.', '', 'MINION', 'RARE', '', '1', '', 'SPELLBURST,STARSHIP_PIECE', 'SPACE', 'Стандартный режим', 'WARLOCK', 110113),
(8607, 'GDB_105', 'Осколочная турель', '3', '2', '4', '<b>Натиск</b>\r\n<b>Неистовство ветра</b>\r\n<b>Часть звездолета</b>', '', 'MINION', 'COMMON', '', '1', '', 'RUSH,STARSHIP_PIECE,WINDFURY', 'SPACE', 'Стандартный режим', 'DEMONHUNTER', 110115),
(8608, 'GDB_106', 'Носовая фигура', '2', '3', '2', '<b><b>Резонанс</b>:</b> активирует <b>предсмертный хрип</b> вашего случайного существа. <b>Часть звездолета</b>.', '', 'MINION', 'EPIC', '', '1', '', 'SPELLBURST,STARSHIP_PIECE', 'SPACE', 'Стандартный режим', 'DEATHKNIGHT', 110117),
(8609, 'GDB_107', 'Сборщик образцов', '3', '2', '6', 'После того как противник разыгрывает существо, атакует это существо. <b>Часть звездолета</b>.', '', 'MINION', 'EPIC', '', '1', '', 'STARSHIP_PIECE,TRIGGER_VISUAL', 'SPACE', 'Стандартный режим', 'HUNTER', 110119),
(8610, 'GDB_108', 'Реактор звездного света', '3', '3', '3', '[x]После того как вы разыгрываете\r\nзаклинание тайной магии,\r\nразыгрывает его повторно<i>\r\n (цели выбираются случайно)</i>.\r\n<b>Часть звездолета</b>', '', 'MINION', 'RARE', '', '1', '', 'STARSHIP_PIECE,TRIGGER_VISUAL', 'SPACE', 'Стандартный режим', 'DRUID', 110233),
(8611, 'GDB_109', 'Сердце Легиона', '2', '3', '2', '<b>Похищение жизни</b>\r\n<b>Часть звездолета</b>', '', 'MINION', 'COMMON', '', '1', '', 'LIFESTEAL,STARSHIP_PIECE', 'SPACE', 'Стандартный режим', 'WARLOCK', 110235),
(8612, 'GDB_110', 'Батарея Скверны', '2', '2', '3', 'После того как это существо атакует, другие ваши существа получают +1 к атаке. <b>Часть звездолета</b>.', '', 'MINION', 'RARE', '', '1', '', 'STARSHIP_PIECE,TRIGGER_VISUAL', 'SPACE', 'Стандартный режим', 'DEMONHUNTER', 110237),
(8613, 'GDB_111', 'Биокапсула', '2', '2', '2', '<b>Предсмертный хрип:</b>\r\nнаносит урон, равный \r\nатаке этого существа, случайному противнику. <b>Часть звездолета</b>.', '', 'MINION', 'RARE', '', '1', '', 'DEATHRATTLE,STARSHIP_PIECE', 'SPACE', 'Стандартный режим', 'HUNTER', 110239),
(8614, 'GDB_112', 'Шпиль уз души', '3', '2', '2', '[x]<b>Предсмертный хрип:</b>\r\n призывает существо,\r\nстоимость которого равна\r\nатаке этого существа <i>(до 10)</i>.\r\n <b>Часть звездолета</b>.', '', 'MINION', 'RARE', '', '1', '', 'DEATHRATTLE,STARSHIP_PIECE', 'SPACE', 'Стандартный режим', 'DEATHKNIGHT', 110878),
(8615, 'GDB_113', 'Пробитый шлюз', '6', '', '', 'Призывает нежить 5/5\r\nс <b>«Провокацией»</b> и дает\r\nвашему герою +5 к здоровью. Расходует 5 <b>трупов</b>, чтобы повторить эффект.', '', 'SPELL', 'RARE', '', '1', '', '', 'SPACE', 'Стандартный режим', 'DEATHKNIGHT', 110880),
(8616, 'GDB_116', 'Зловещее создание', '1', '1', '3', '<b>Изгой</b>. <b>Резонанс:</b>\r\nвы перемешиваете\r\nкарты в вашей руке.', '', 'MINION', 'EPIC', '', '1', '', 'OUTCAST,SPELLBURST', 'SPACE', 'Стандартный режим', 'DEMONHUNTER', 110886),
(8617, 'GDB_117', 'Мятежный капитан Дирдра', '4', '5', '4', '<b>Натиск</b>. <b>Боевой клич:</b>\r\nзамешивает в вашу колоду\r\nвсех 8 астронавтов. <b>Предсмертный хрип:</b> вы берете одного из них.', '', 'MINION', 'LEGENDARY', '', '1', '', 'BATTLECRY,DEATHRATTLE,RUSH', 'SPACE', 'Стандартный режим', 'DEMONHUNTER', 110908),
(8618, 'GDB_118', 'Зор''тот Сокрушитель Звезд', '5', '5', '5', '<b>Боевой клич</b>: добавляет по звезде с обеих сторон в вашей руке. Когда они сталкиваются, наносит [x] 5 ед. урона противникам.', '', 'MINION', 'LEGENDARY', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', 'DEMONHUNTER', 110923),
(8619, 'GDB_119', 'Срочное собрание', '1', '', '', '[x]Вы кладете в руку двух \r\nастронавтов 4/4. Между ними\r\n появляется случайный демон\r\n за (3) или меньше.', '', 'SPELL', 'EPIC', '', '1', '', '', 'SPACE', 'Стандартный режим', 'DEMONHUNTER', 111075),
(8620, 'GDB_120', 'Экзодар', '7', '6', '8', '<b>Боевой клич:</b> если вы строите <b>звездолет</b>,\r\nвы запускаете его\r\n и выбираете протокол!', '', 'MINION', 'Free', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', '', 110326),
(8621, 'GDB_121', 'Зловещий огонь', '2', '2', '3', '[x]<b>Боевой клич</b>: демоны,\r\nкоторых не было в вашей\r\nколоде в начале матча,\r\n стоят на (1) меньше\r\nдо конца матча.', '', 'MINION', 'COMMON', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', 'WARLOCK', 111133),
(8622, 'GDB_122', 'Инфернальная стратагема', '3', '', '', '[x]Дает существу +3/+3.\r\nЕсли это демон,\r\nваш следующий демон\r\nстоит на (2) меньше.', '', 'SPELL', 'RARE', '', '1', '', '', 'SPACE', 'Стандартный режим', 'WARLOCK', 111139),
(8623, 'GDB_123', 'Похищающий луч', '1', '', '', '[x]Вы получаете случайного\r\n демона. Его стоимость\r\nуменьшается на (2).\r\nМожно разыгрывать\r\nмногократно на этом ходу.', '', 'SPELL', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', 'WARLOCK', 111169),
(8624, 'GDB_124', 'Дурное знамение', '6', '', '', 'Через 2 хода вы призываете двух демонов 6/6 с <b>«Провокацией»</b>. Если вы строите <b>звездолет</b>, то призываете их немедленно.', '', 'SPELL', 'RARE', '', '1', '', '', 'SPACE', 'Стандартный режим', 'WARLOCK', 111176),
(8625, 'GDB_125', 'Камень здоровья', '0', '', '', '<b>Можно обменять</b>\r\nВосполняет вашему герою здоровье в объеме урона, полученного на этом ходу.@ <i>(@)</i>', '', 'SPELL', 'EPIC', '', '1', '', 'TRADEABLE,TRIGGER_VISUAL', 'SPACE', 'Стандартный режим', 'WARLOCK', 111177),
(8626, 'GDB_126', 'Черная дыра', '8', '', '', 'Уничтожает всех существ, кроме демонов.', '', 'SPELL', 'EPIC', '', '1', '', '', 'SPACE', 'Стандартный режим', 'WARLOCK', 111178),
(8627, 'GDB_127', 'К''ара Темная Звезда', '3', '3', '3', '[x]<b><b>Резонанс</b>:</b> похищает 2 ед. здоровья\r\nу случайного противника.\r\n <i>(Заклинания Тьмы не рассеивают\r\n этот <b>резонанс</b>.)</i>', '', 'MINION', 'LEGENDARY', '', '1', '', 'SPELLBURST', 'SPACE', 'Стандартный режим', 'WARLOCK', 111179),
(8628, 'GDB_128', 'Архимонд', '6', '6', '6', '[x]<b>Боевой клич</b>: призывает\r\nвсех демонов, разыгранных\r\nвами в этом матче, которых\r\nне было в вашей колоде\r\nв начале матча.', '', 'MINION', 'LEGENDARY', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', 'WARLOCK', 111301),
(8629, 'GDB_129', 'Дева рока', '4', '4', '4', '[x]<b>Боевой клич:</b> вы берете карту\r\nиз колоды противника. Если вы\r\nне разыгрываете ее на этом ходу,\r\nто кладете ее обратно.', '', 'MINION', 'EPIC', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', '', 111303),
(8630, 'GDB_130', 'Кристаллосварщик', '2', '2', '3', '<b>Провокация</b>\r\n<b>Боевой клич:</b> если вы строите <b>звездолет</b>, получает +2/+2.', '', 'MINION', 'COMMON', '', '1', '', 'BATTLECRY,TAUNT', 'SPACE', 'Стандартный режим', '', 111304),
(8631, 'GDB_131', 'Велен, предводитель изгнанников', '7', '7', '7', '<b>Провокация</b>. <b>Предсмертный хрип</b>: активирует <b>«Боевые кличи»</b> и <b>«Предсмертные хрипы»</b> всех\r\n[x]других дренеев, разыгранных\r\nвами в этом матче.', '', 'MINION', 'LEGENDARY', '', '1', '', 'DEATHRATTLE,TAUNT', 'SPACE', 'Стандартный режим', '', 111306),
(8632, 'GDB_132', 'Неутомимый страж гнева', '3', '4', '2', '<b>Боевой клич</b>: наносит\r\n[x]2 ед. урона существу\r\n противника. Если оно погибает,\r\n вы <b>раскапываете</b> демона.', '', 'MINION', 'RARE', '', '1', '', 'BATTLECRY,DISCOVER', 'SPACE', 'Стандартный режим', '', 111330),
(8633, 'GDB_133', 'Карманное измерение', '4', '', '', 'Вы <b>раскапываете</b> заклинание. Эффект повторяется, пока вам не встретится повтор.', '', 'SPELL', 'EPIC', '', '1', '', 'DISCOVER', 'SPACE', 'Стандартный режим', 'MAGE', 111344),
(8634, 'GDB_134', 'Пилот каронитового судна', '6', '4', '3', 'В конце вашего хода\r\nнаносит 3 ед. урона\r\nслучайному противнику.\r\n<b>Резонанс</b>: призывает пилота каронитового судна.', '', 'MINION', 'RARE', '', '1', '', 'SPELLBURST,TRIGGER_VISUAL', 'SPACE', 'Стандартный режим', 'MAGE', 111345),
(8635, 'GDB_135', 'Искусный механолог', '4', '4', '5', '<b>Боевой клич</b>: следующий разыгранный вами дреней восполнит кристаллы маны в количестве, равном\r\n показателю его атаки.', '', 'MINION', 'RARE', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', 'MAGE', 111346),
(8636, 'GDB_136', 'Экзарх Хатаару', '5', '5', '5', '<b>Боевой клич:</b> вы <b>раскапываете</b> заклинание. Его стоимость уменьшается на (1). Если вы разыгрываете его на этом ходу, эффект повторяется.', '', 'MINION', 'LEGENDARY', '', '1', '', 'BATTLECRY,DISCOVER', 'SPACE', 'Стандартный режим', 'MAGE', 111893),
(8637, 'GDB_137', 'Манускрипт ясности', '3', '', '', '[x]Вы берете 2 существ.\r\nЕсли эта карта стоит (0),\r\nони получают +2/+1.', '', 'SPELL', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', 'PALADIN', 111644),
(8638, 'GDB_138', 'Манускрипт божественности', '4', '', '', '[x]Дает существу +3/+3.\r\nЕсли эта карта стоит (0),\r\nвы возвращаете ее в руку\r\nв конце вашего хода.', '', 'SPELL', 'EPIC', '', '1', '', '', 'SPACE', 'Стандартный режим', 'PALADIN', 111647),
(8639, 'GDB_139', 'Манускрипт веры', '6', '', '', 'Вы призываете\r\nтрех дренеев 3/3\r\nс <b>«Божественным щитом»</b>.\r\nЕсли эта карта стоит (0),\r\nони получают <b>«Натиск»</b>.', '', 'SPELL', 'RARE', '', '1', '', '', 'SPACE', 'Стандартный режим', 'PALADIN', 111650),
(8640, 'GDB_140', 'Небесная аура', '6', '', '', '[x]Пока вы контролируете\r\nровно одно существо, его\r\n атака и здоровье равны 10.\r\nДействует 3 |4(ход,хода,ходов).', '', 'SPELL', 'EPIC', '', '1', '', '', 'SPACE', 'Стандартный режим', 'PALADIN', 111651),
