(8758, 'SC_003', 'Королева стаи', '3', '2', '5', 'В конце вашего хода\r\nвы получаете личинку,\r\nкоторая превращается в случайных зергов.', '', 'MINION', 'COMMON', '', '1', '', 'TRIGGER_VISUAL', 'SPACE', 'Стандартный режим', '', 112834),
(8759, 'SC_004', 'Керриган, Королева Клинков', '7', '', '30', '<b>Боевой клич:</b> призывает двух королев стаи 2/5. Наносит противникам 3 ед. урона.', '', 'HERO', 'LEGENDARY', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', '', 112846),
(8760, 'SC_008', 'Гидралиск', '3', '4', '2', '<b>Боевой клич:</b> наносит\r\n2 ед. урона случайному противнику. Эффект\r\n повторяется за каждого\r\nдругого вашего зерга.', '', 'MINION', 'RARE', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', 'HUNTER', 112859),
(8761, 'SC_009', 'Скрытень', '4', '2', '6', 'После того как ваше существо атакует, наносит 1 ед. урона случайному противнику\r\n<i>(или 2, если ваше существо является зергом)</i>.', '', 'MINION', 'RARE', '', '1', '', 'TRIGGER_VISUAL', 'SPACE', 'Стандартный режим', 'DEMONHUNTER', 112862),
(8762, 'SC_010', 'Зерглинг', '1', '1', '1', '<b>Боевой клич:</b> призывает копию этого существа.', '', 'MINION', 'RARE', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', '', 112867),
(8763, 'SC_011', 'Опухоль', '2', '', '', 'Ваши зерги получают +1 к атаке и <b>«Натиск»</b>. Действует 3 хода.', '', 'SPELL', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', 'DEMONHUNTER', 112869),
(8764, 'SC_012', 'Таракан', '2', '2', '2', 'Когда вы берете эту карту,\r\nвы получаете ее копию.\r\n<b>Боевой клич:</b> получает +1/+2,\r\n[x]если у вас под контролем\r\nесть другой зерг.', '', 'MINION', 'RARE', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', 'HUNTER', 112872),
(8765, 'SC_013', 'Пострел', '8', '3', '4', '<b>Боевой клич:</b> призывает четырех случайных мурлоков и стреляет ими по существам противника. <i>(Вы выбираете цели!)</i>', '', 'MINION', 'LEGENDARY', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', 'NEUTRAL', 113249),
(8766, 'SC_015', 'Червь Нидуса', '3', '', '', '[x]Вы берете двух зергов.\r\nОни стоят на (1) меньше.', '', 'SPELL', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', '', 113576),
(8767, 'SC_018', 'Стрекоза', '4', '5', '3', '<b>Боевой клич:</b> призывает существо из руки противника. Другие ваши зерги\r\n[x]получают <b>«Перерождение»</b>\r\nи атакуют его.', '', 'MINION', 'RARE', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', 'DEATHKNIGHT', 113663),
(8768, 'SC_019', 'Пещера ультралисков', '3', '', '3', 'Наносит 1 ед. урона\r\nвсем противникам.\r\n<b>Предсмертный хрип:</b>\r\nпризывает ультралиска\r\n8/8 с <b>«Натиском»</b>.', '', 'LOCATION', 'COMMON', '', '1', '', 'DEATHRATTLE', 'SPACE', 'Стандартный режим', 'WARLOCK', 113664),
(8769, 'SC_020', 'Поглощение', '1', '', '', 'Уменьшает прочность\r\nвашей области на 1\r\nи восстанавливает\r\n#8 ед. здоровья\r\nвашему герою.', '', 'SPELL', 'RARE', '', '1', '', 'ImmuneToSpellpower', 'SPACE', 'Стандартный режим', 'WARLOCK', 113667),
(8770, 'SC_021', 'Эволюционная камера', '2', '', '', 'Ваши существа получают +1 к атаке. Ваши зерги получают еще +1/+1.', '', 'SPELL', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', 'HUNTER', 113671),
(8771, 'SC_022', 'Муталиск', '4', '5', '2', 'Также наносит урон существам по обе стороны от цели\r\n <i>(если соседней цели нет,[x]\r\n    атакует героя противника)</i>.', '', 'MINION', 'RARE', '', '1', '', 'TRIGGER_VISUAL', 'SPACE', 'Стандартный режим', 'DEMONHUNTER', 113672),
(8772, 'SC_023', 'Ползучий плеточник', '2', '1', '6', '<b>Провокация</b>\r\nНе может атаковать.\r\nПолучает +3 к атаке, если вы контролируете область.', '', 'MINION', 'COMMON', '', '1', '', 'CANT_ATTACK,TAUNT', 'SPACE', 'Стандартный режим', 'WARLOCK', 113673),
(8773, 'SC_400', 'Джим Рейнор', '7', '', '30', '<b>Боевой клич:</b> повторно запускает все <b>звездолеты</b>, запущенные вами\r\nв этом матче.', '', 'HERO', 'LEGENDARY', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', '', 112815),
(8774, 'SC_401', 'КСМ', '1', '1', '3', '[x]<b>Боевой клич:</b> ваш\r\nследующий запуск <b>звездолета</b>\r\nстоит на (2) меньше.', '', 'MINION', 'RARE', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', '', 112820),
(8775, 'SC_403', 'Космопорт', '2', '', '2', 'Призывает <b>часть звездолета</b> 2/1\r\nс эффектом\r\nпри запуске.', '', 'LOCATION', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', '', 112856),
(8776, 'SC_404', 'Демонтаж бункера', '3', '', '', '[x]Призывает двух морпехов\r\n2/2 с <b>«Провокацией»</b>.\r\nВаш следующий\r\nзапуск <b>звездолета</b>\r\nстоит на (2) меньше.', '', 'SPELL', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', 'PALADIN', 112858),
(8777, 'SC_405', 'Ультраконденсатор', '2', '1', '1', '[x]<b>Часть звездолета</b>\r\n <b>Боевой клич:</b> получает\r\n+1/+1 за каждое другое\r\nваше существо. Также\r\n  срабатывает при запуске.', '', 'MINION', 'RARE', '', '1', '', 'BATTLECRY,STARSHIP_PIECE,TRIGGER_VISUAL', 'SPACE', 'Стандартный режим', 'PALADIN', 112866);
