(8778, 'SC_406', 'Орудие «Ямато»', '4', '3', '3', '<b>Часть звездолета</b>\r\n<b>Боевой клич:</b> уничтожает случайное существо противника. Также срабатывает\r\nпри запуске.', '', 'MINION', 'RARE', '', '1', '', 'BATTLECRY,STARSHIP_PIECE', 'SPACE', 'Стандартный режим', 'WARRIOR', 112873),
(8779, 'SC_407', 'Захват цели', '1', '', '', 'Здоровье существа становится равно 1. Ваш следующий запуск <b>звездолета</b> стоит на (2) меньше.', '', 'SPELL', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', 'SHAMAN', 112876),
(8780, 'SC_408', 'Призрак', '4', '6', '2', '[x]<b>Маскировка</b>\r\n<b>Боевой клич:</b> если вы строите\r\n <b>звездолет</b>, уничтожает карту\r\nс наименьшей стоимостью\r\nв руке противника.', '', 'MINION', 'COMMON', '', '1', '', 'BATTLECRY,STEALTH', 'SPACE', 'Стандартный режим', '', 112912),
(8781, 'SC_409', 'Ракетный модуль', '2', '1', '3', '<b>Часть звездолета</b>\r\n<b>Боевой клич:</b> наносит 1 ед. урона противникам. Также срабатывает\r\nпри запуске.', '', 'MINION', 'COMMON', '', '1', '', 'BATTLECRY,STARSHIP_PIECE', 'SPACE', 'Стандартный режим', 'SHAMAN', 113209),
(8782, 'SC_410', 'Взлет', '3', '', '', 'Вы берете 2 карты терранов. Призывает\r\n<b>часть звездолета</b> 2/1\r\nс эффектом при запуске.', '', 'SPELL', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', '', 113211),
(8783, 'SC_411', 'Фугасные гранаты', '1', '', '', 'Наносит $2 ед. урона. Вы получаете 2 ед. брони. Ваш следующий\r\nзапуск <b>звездолета</b>\r\nстоит на (2) меньше.', '', 'SPELL', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', 'WARRIOR', 113212),
(8784, 'SC_412', '«Геллион»', '4', '4', '4', 'Другие ваши существа\r\nполучают +1 к атаке. <i>(Сменяет режим, если вы запустили <b>звездолет</b> в этом матче.)</i>', '', 'MINION', 'RARE', '', '1', '', 'AURA', 'SPACE', 'Стандартный режим', 'PALADIN', 113855),
