(8786, 'SC_414', '«Тор»', '8', '8', '8', '<b>Боевой клич:</b>\r\nнаносит 5 ед. урона. <i>(Сменяет режим, если вы запустили <b>звездолет</b> в этом матче.)</i>', '', 'MINION', 'RARE', '', '1', '', 'BATTLECRY', 'SPACE', 'Стандартный режим', 'WARRIOR', 113869),
(8787, 'SC_750', 'Темпоральное ускорение', '4', '', '', '[x]Вы берете 2 карты\r\n протоссов. Призывает\r\nзилота 3/4 с <b>«Рывком»</b>.', '', 'SPELL', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', '', 113163),
(8788, 'SC_751', 'Врата искривления', '4', '', '3', 'Ваш следующий протосс стоит на (3) меньше.', '', 'LOCATION', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', '', 113164),
