(8792, 'SC_755', 'Вызов пилонов', '0', '', '', 'Ваша следующая карта протоссов на этом ходу стоит на (2) меньше.', '', 'SPELL', 'COMMON', '', '1', '', '', 'SPACE', 'Стандартный режим', 'DRUID', 113173),
