(8794, 'SC_757', 'Иллюзия', '1', '', '', 'Призывает копию вашего протосса. Она получает двойной урон.', '', 'SPELL', 'RARE', '', '1', '', '', 'SPACE', 'Стандартный режим', 'PRIEST', 113176),
