(8804, 'CORE_EDR_001', 'Болтливый шкаф', '3', '2', '4', '<b>Боевой клич:</b> вы кладете в руку 2 случайных заклинания мага.', '', 'MINION', 'Free', '', '1', '', 'BATTLECRY', 'PLACEHOLDER_202204', 'Стандартный режим', 'MAGE', 117307),
