(8928, 'EDR_849', 'Преданный Сну ящер', '1', '2', '1', 'После того как вы разыгрываете существо, оно получает случайный <b>бонусный эффект</b>.', '', 'MINION', 'COMMON', '', '1', '', 'TRIGGER_VISUAL', 'EMERALD_DREAM', 'Стандартный режим', '', 114933),
(8929, 'EDR_852', 'Рыцарь Горького Цветка', '2', '2', '3', '<b>Боевой клич:</b> <b>заряжает</b> вашу силу героя.', '', 'MINION', 'COMMON', '', '1', '', 'BATTLECRY', 'EMERALD_DREAM', 'Стандартный режим', '', 114935),
(8930, 'EDR_853', 'Бролл Медвежья Шкура', '5', '3', '5', 'Когда вы применяете заклинание, призывает [x]случайного питомца.', '', 'MINION', 'LEGENDARY', '', '1', '', 'TRIGGER_VISUAL', 'EMERALD_DREAM', 'Стандартный режим', 'HUNTER', 114857),
(8931, 'EDR_856', 'Повелитель кошмаров Ксавий', '4', '4', '4', '[x]<b>Боевой клич:</b> вы\r\n<b>раскапываете</b> существо\r\nиз своей колоды. Оно\r\n   получает <b>«Темный дар»</b>.', '', 'MINION', 'LEGENDARY', '', '1', '', 'BATTLECRY,DISCOVER', 'EMERALD_DREAM', 'Стандартный режим', '', 115139),
(8932, 'EDR_860', 'Блистающий ткач Снов', '4', '4', '4', '<b>Боевой клич:</b> если вы <b>зарядили</b> вашу силу героя дважды, наносит\r\n5 ед. урона существу.', '', 'MINION', 'EPIC', '', '1', '', 'BATTLECRY', 'EMERALD_DREAM', 'Стандартный режим', '', 114076),
