(8940, 'EDR_889', 'Продавец лепестков', '2', '1', '4', 'В конце вашего хода другой ваш\r\nслучайный дракон\r\nполучает +1/+1.', '', 'MINION', 'COMMON', '', '1', '', 'TRIGGER_VISUAL', 'EMERALD_DREAM', 'Стандартный режим', '', 115191),
(8941, 'EDR_890', 'Кошмарный драконид', '3', '4', '2', '<b>Предсмертный хрип:</b> уменьшает стоимость крайней правой карты у вас в руке на (2).', '', 'MINION', 'COMMON', '', '1', '', 'DEATHRATTLE', 'EMERALD_DREAM', 'Стандартный режим', 'DEMONHUNTER', 114496),
(8942, 'EDR_891', 'Прожорливый охотник Скверны', '5', '5', '3', '[x]<b>Предсмертный хрип:</b>\r\nвоскрешает ваше существо\r\n за (4) или меньше\r\nс <b>«Предсмертным хрипом»</b> \r\nи призывает его копию.', '', 'MINION', 'RARE', '', '1', '', 'DEATHRATTLE', 'EMERALD_DREAM', 'Стандартный режим', 'DEMONHUNTER', 114497),
(8943, 'EDR_892', 'Свирепый сквернотопырь', '7', '7', '5', '[x]<b>Предсмертный хрип:</b>\r\nвоскрешает другое ваше\r\nсущество за (5) или больше\r\nс <b>«Предсмертным хрипом»</b>\r\nи призывает его копию.', '', 'MINION', 'EPIC', '', '1', '', 'DEATHRATTLE', 'EMERALD_DREAM', 'Стандартный режим', 'DEMONHUNTER', 114498),
(8944, 'EDR_895', 'Авиана, избранница Элуны', '9', '7', '11', '<b>Боевой клич:</b> начинает лунный цикл с длительностью три хода. Когда взойдет полная луна, ваши карты в этом матче будут стоить (1).', '', 'MINION', 'LEGENDARY', '', '1', '', 'BATTLECRY', 'EMERALD_DREAM', 'Стандартный режим', 'PRIEST', 115264),
(8945, 'EDR_940', 'Веселый лунный совух', '4', '3', '6', 'В конце вашего хода вы получаете +1 к броне. Эффект повторяется за каждый огонек под вашим контролем.', '', 'MINION', 'RARE', '', '1', '', 'TRIGGER_VISUAL', 'EMERALD_DREAM', 'Стандартный режим', 'MAGE', 115805),
(8946, 'EDR_941', 'Звездный поток', '3', '', '', 'Наносит $1 ед. урона существу. <i>(Улучшается за каждое ваше существо, погибшее в течение матча.)</i>', '', 'SPELL', 'COMMON', '', '1', '', '', 'EMERALD_DREAM', 'Стандартный режим', 'MAGE', 115866),
(8947, 'EDR_942', 'Любопытное облако', '4', '3', '5', 'В конце вашего хода\r\nваш герой получает [x] <b>«Божественный щит»</b>.', '', 'MINION', 'COMMON', '', '1', '', 'TRIGGER_VISUAL', 'EMERALD_DREAM', 'Стандартный режим', '', 115867),
(8948, 'EDR_970', 'Жрица калдорай', '3', '3', '3', '<b>Боевой клич:</b> существа противника получают -2 к атаке до вашего следующего хода. <b>Заряжает</b> вашу силу героя.', '', 'MINION', 'RARE', '', '1', '', 'BATTLECRY', 'EMERALD_DREAM', 'Стандартный режим', 'PRIEST', 115461),
(8949, 'EDR_971', 'Смотрительница зверьков', '1', '2', '2', 'В конце вашего хода восстанавливает [x]#3 ед. здоровья\r\nобоим героям.', '', 'MINION', 'COMMON', '', '1', '', 'TRIGGER_VISUAL', 'EMERALD_DREAM', 'Стандартный режим', '', 115938),
(8950, 'EDR_978', 'Луговой скиталец', '8', '6', '11', '<b>Провокация</b>. <b>Предсмертный хрип:</b> кладет в конец вашей колоды лугового скитальца стоимостью (1).', '', 'MINION', 'COMMON', '', '1', '', 'DEATHRATTLE,TAUNT', 'EMERALD_DREAM', 'Стандартный режим', '', 117511),
(8951, 'EDR_979', 'Древо древности', '5', '5', '5', '<b>Спячка</b>: 2 хода.\r\nПока остается в <b>спячке</b>,\r\nвы получаете +5 к броне\r\nи берете карту в конце\r\nвашего хода.', '', 'MINION', 'EPIC', '', '1', '', '', 'EMERALD_DREAM', 'Стандартный режим', '', 117302),
(8952, 'EDR_999', 'Зубастый зеленожабр', '1', '1', '1', '<b>Боевой клич:</b> вы получаете случайного мурлока.', '', 'MINION', 'COMMON', '', '1', '', 'BATTLECRY', 'EMERALD_DREAM', 'Стандартный режим', '', 116256),
