(9112, 'TLC_109', 'Добытчик реликвий', '3', '3', '3', '[x]<b>Боевой клич:</b> уничтожает\r\nверхнюю карту вашей колоды.\r\nВы <b>раскапываете</b> карту\r\nтой же редкости.', '', 'MINION', 'COMMON', '', '1', '', 'BATTLECRY,DISCOVER', 'THE_LOST_CITY', 'Стандартный режим', '', 117889),
