(9337, 'TIME_609', 'Командир следопытов Сильвана', '3', '2', '4', '[x]<b>Герой саги</b>. <b>Боевой клич:</b>\nнаносит противникам 2 ед. урона.\nЕсли вы уже разыграли Аллерию\nили Верису, эффект повторяется\nза каждую из них.', '', 'MINION', 'LEGENDARY', '', '1', '', 'BATTLECRY,DISCOVER', 'TIME_TRAVEL', 'Стандартный режим', 'HUNTER', 119705),
(9338, 'TIME_609t1', 'Командир следопытов Сильвана (2 - Капитан следопытов Аллерия)', '3', '2', '4', '[x]<b>Боевой клич:</b> существа в вашей\r\nколоде получают +1/+1. Если\r\nвы уже разыграли Аллерию или\r\nСильвану, эффект повторяется\r\nза каждую из них.', '', 'MINION', '', '', '1', '', 'BATTLECRY', 'TIME_TRAVEL', 'Стандартный режим', 'HUNTER', 119706),
(9339, 'TIME_620', 'Безвременная смерть', '2', '', '', '<b>Секрет:</b> когда ваше существо погибает\r\nна следующий ход после того, как вы его разыграли,\r\nвы призываете его снова.', '', 'SPELL', 'RARE', '', '1', '', 'SECRET', 'TIME_TRAVEL', 'Стандартный режим', 'HUNTER', 121210),
(9340, 'TIME_810', 'Луносвет: прошлое', '4', '', '3', 'Наносит 5 ед. урона случайному существу противника. <i>Переходит в настоящее!</i>', '', 'LOCATION', 'EPIC', '', '1', '', '', 'TIME_TRAVEL', 'Стандартный режим', 'HUNTER', 119166),
(9341, 'TIME_006', 'Зеркальное измерение', '1', '', '', 'Призывает существо\r\n0/4 с <b>«Провокацией»</b>.\r\nЕсли у вас в руке есть дракон, призывает еще одно.', '', 'SPELL', 'COMMON', '', '1', '', '', 'TIME_TRAVEL', 'Стандартный режим', 'MAGE', 119541),
(9342, 'TIME_852', 'Лазурная королева Синдрагоса', '5', '2', '8', '<b>Герой саги</b>\r\nЕсли вы контролируете еще\r\nодного дракона, ваши\r\nзаклинания тайной магии\r\nстоят на (2) меньше.', '', 'MINION', 'LEGENDARY', '', '1', '', 'AURA', 'TIME_TRAVEL', 'Стандартный режим', 'MAGE', 119524),
(9343, 'TIME_852t3', 'Лазурная королева Синдрагоса (2 - Лазурный камень клятвы)', '5', '2', '8', 'Если вы контролируете еще одного дракона, ваши заклинания тайной магии применяются дважды.', '', 'MINION', '', '', '1', '', 'AURA', 'TIME_TRAVEL', 'Стандартный режим', 'MAGE', 119527),
(9344, 'TIME_852t1', 'Лазурная королева Синдрагоса (1 - Лазурный король Малигос)', '5', '', '', 'Призывает ваших драконов, погибших в этом матче.', '', 'SPELL', '', '', '1', '', '', 'TIME_TRAVEL', 'Стандартный режим', 'MAGE', 119525),
(9345, 'TIME_855', 'Чародейский обстрел', '3', '', '', 'Наносит $3 ед. урона выбранному противнику и $2 ед. урона двум другим случайным противникам.', '', 'SPELL', 'COMMON', '', '1', '', '', 'TIME_TRAVEL', 'Стандартный режим', 'MAGE', 119528),
(9346, 'TIME_856', 'Алгет''арский инструктор', '5', '4', '7', '<b>Урон от заклинаний +2</b>.', '', 'MINION', 'COMMON', '', '1', '', 'SPELLPOWER', 'TIME_TRAVEL', 'Стандартный режим', 'MAGE', 119632),
(9347, 'TIME_857', 'Манипуляции с временем', '4', '', '', 'Вы <b>раскапываете</b> два заклинания тайной магии из прошлого. Они стоят на (2) меньше.', '', 'SPELL', 'RARE', '', '1', '', 'DISCOVER', 'TIME_TRAVEL', 'Стандартный режим', 'MAGE', 119633),
(9348, 'TIME_858', 'Темпоральный голем', '7', '5', '5', '<b>Боевой клич:</b> наносит существу противника 5 ед. урона. Вы берете карты в количестве избыточного урона.', '', 'MINION', 'RARE', '', '1', '', 'BATTLECRY', 'TIME_TRAVEL', 'Стандартный режим', 'MAGE', 119649),
(9349, 'TIME_859', 'Аномализация', '7', '', '', '[x]Призывает случайных существ\r\nза (10) и (1). Перемешивает\r\nих характеристики.', '', 'SPELL', 'EPIC', '', '1', '', '', 'TIME_TRAVEL', 'Стандартный режим', 'MAGE', 119691),
(9350, 'TIME_860', 'Загадочный безликий', '2', '2', '2', '[x]<b>Боевой клич:</b> вы просматриваете\r\n2 случайных <b>секрета</b>.\r\nВы выбираете и разыгрываете\r\nодин из них, а второй приме[d]няется для противника.', '', 'MINION', 'EPIC', '', '1', '', 'BATTLECRY', 'TIME_TRAVEL', 'Стандартный режим', 'MAGE', 119740),
(9351, 'TIME_861', 'Цикличная Токи', '3', '3', '3', '<b>Боевой клич:</b> вы получаете\r\n4 случайных заклинания из прошлого. Разыграв все 4,\r\nвы получаете еще одну цикличную Токи.', '', 'MINION', 'LEGENDARY', '', '1', '', 'BATTLECRY', 'TIME_TRAVEL', 'Стандартный режим', 'MAGE', 119741),
(9352, 'TIME_002', 'Маг вечности', '5', '3', '5', '<b>Перемотка</b>\r\n<b>Боевой клич:</b> вы получаете\r\nдва случайных заклинания своего класса.', '', 'MINION', 'COMMON', '', '1', '', 'BATTLECRY', 'TIME_TRAVEL', 'Стандартный режим', '', 119312);
