(9354, 'TIME_024', 'Дорнозму Освобожденный', '9', '8', '8', '[x]<b>Боевой клич:</b> в начале\r\nвашего следующего хода\r\nатака этого существа ста[d]     новится БЕСКОНЕЧНОЙ!    ', '', 'MINION', 'LEGENDARY', '', '1', '', 'BATTLECRY', 'TIME_TRAVEL', 'Стандартный режим', '', 120266),
(9355, 'TIME_035', 'Машина времени', '6', '6', '6', '<b>Провокация</b>\r\n<b>Предсмертный хрип:</b>\r\nвы получаете случайную\r\nкарту с <b>«Перемоткой»</b>.', '', 'MINION', 'COMMON', '', '1', '', 'DEATHRATTLE,TAUNT', 'TIME_TRAVEL', 'Стандартный режим', '', 120506),
(9356, 'TIME_040', 'Угасающее воспоминание', '4', '6', '3', '[x]<b>Предсмертный хрип:</b> вы\r\nполучаете случайное суще[d]    ство из прошлого за (5).    ', '', 'MINION', 'COMMON', '', '1', '', 'DEATHRATTLE', 'TIME_TRAVEL', 'Стандартный режим', '', 120782),
(9357, 'TIME_041', 'Прозорливый праотец', '4', '4', '4', '[x]<b>Провокация</b>. <b>Боевой клич:</b>\r\nвы просматриваете 3 карты.\r\nУгадайте, какая из них есть\r\nв руке противника, чтобы\r\nполучить +4 к здоровью.', '', 'MINION', 'EPIC', '', '1', '', 'BATTLECRY', 'TIME_TRAVEL', 'Стандартный режим', '', 120784),
(9358, 'TIME_045', 'Дракончик Бесконечности', '3', '1', '4', '<b>Яд</b>\r\n<b>Перерождение</b>', '', 'MINION', 'COMMON', '', '1', '', 'POISONOUS,REBORN', 'TIME_TRAVEL', 'Стандартный режим', '', 120856),
(9359, 'TIME_046', 'Киборг-патриарх', '3', '3', '12', '<b>Провокация</b>\r\n<b>Спячка:</b> 3 хода.', '', 'MINION', 'COMMON', '', '1', '', 'TAUNT', 'TIME_TRAVEL', 'Стандартный режим', '', 120857),
(9360, 'TIME_047', 'Коварный койот', '5', '5', '3', '<b>Маскировка</b>\r\nСтоит на (1) меньше за каждый раз, когда герой противника\r\n[x] получил урон на этом ходу.', '', 'MINION', 'COMMON', '', '1', '', 'STEALTH', 'TIME_TRAVEL', 'Стандартный режим', '', 120859),
