(9373, 'TIME_060', 'Квантовый дестабилизатор', '3', '4', '9', '[x]Получает удвоенный урон\r\nиз всех источников.', '', 'MINION', 'COMMON', '', '1', '', '', 'TIME_TRAVEL', 'Стандартный режим', '', 120976),
(9374, 'TIME_061', 'Вневременная причинность', '2', '3', '2', '[x]<b>Боевой клич:</b>\r\nсортирует вашу колоду\r\nв обратном порядке.', '', 'MINION', 'EPIC', '', '1', '', 'BATTLECRY', 'TIME_TRAVEL', 'Стандартный режим', '', 120977),
(9375, 'TIME_062', 'Хранительница летописи', '4', '3', '6', '[x]<b>Боевой клич:</b> если\r\nу вас в руке есть дракон,\r\nполучает<b> «Провокацию»</b>\r\n      и <b>«Божественный щит»</b>.   ', '', 'MINION', 'COMMON', '', '1', '', 'BATTLECRY', 'TIME_TRAVEL', 'Стандартный режим', '', 120979),
(9376, 'TIME_063', 'Повелитель времени Ноздорму', '3', '8', '8', '[x]<b>Спячка</b>: 5 ходов.\r\n<b>Натиск</b>. После того как вы\r\nразыгрываете карту из нового\r\nдополнения, время спячки\r\nсокращается на 1 ход.', '', 'MINION', 'LEGENDARY', '', '1', '', 'RUSH', 'TIME_TRAVEL', 'Стандартный режим', '', 120981),
