(10049, 'CATA_133', 'Радужный летунчик', '5', '4', '5', '<b>Неуловимость</b>\r\n В конце вашего хода\r\nдругие ваши существа получают +1/+1.', '', 'MINION', 'COMMON', '', '1', '', 'TRIGGER_VISUAL', 'CATACLYSM', 'Стандартный режим', 'DRUID', 122970),
(10050, 'CATA_134', 'Чащобный круг', '3', '', '', '<b>Раскол</b>\r\nПризывает двух древней 2/2. Ваши существа получают «<b>Предсмертный хрип:</b> призывает древня 2/2».', '', 'SPELL', 'RARE', '', '1', '', '', 'CATACLYSM', 'Стандартный режим', 'DRUID', 122971),
(10051, 'CATA_135', 'Мшистые узы', '2', '', '', '[x]Призывает двух\r\nголемов 1/2. Вы расходуете\r\nвсю ману, и они получают\r\n+1/+1 за каждую единицу\r\nпотраченной маны.', '', 'SPELL', 'RARE', '', '1', '', '', 'CATACLYSM', 'Стандартный режим', 'DRUID', 123023),
(10052, 'CATA_136', 'Триумф Азшары', '1', '', '', 'Вы замешиваете в свою колоду 5 случайных существ за (8) или больше. Их характеристики удваиваются.', '', 'SPELL', 'EPIC', '', '1', '', '', 'CATACLYSM', 'Стандартный режим', 'DRUID', 122975),
